"    dbg_sram.cnt_clr:write(slice, 1, lane)\n" \
"    dump_adc_output(slice, lane)\n" \
"    local data = dump_sram(slice, lane, 1)\n" \
"    dbg_sram.cnt_clr:write(slice, 0, lane)\n" \
"    return data\n" \
"end\n" \
"\n" \
"return sram\n";
