"            fort.printf_ln(ftable, \"%d|%s\", lane, mode_name)\n" \
"        else\n" \
"            local enable = credo.fecana_query(slice, lane)\n" \
"            if not enable then\n" \
"                fort.printf_ln(ftable, \"%d|%s|NO\", lane, mode_name)\n" \
"            else\n" \
"                local duration = credo.fecana_get_duration(slice, lane)\n" \
"                local pre_fec, post_fec = credo.fecana_get_counter(slice, lane)\n" \
"                local pre_fec_ber = credo.fecana_get_error_rate(slice, lane, 4, 0)\n" \
"                local post_fec_ber = credo.fecana_get_error_rate(slice, lane, 6, 0)\n" \
"                fort.printf_ln(ftable, \"%d|%s|YES|%.1f|%d|%d|%.3e|%.3e\", lane, mode_name, duration / 1000, pre_fec,\n" \
"                               post_fec, pre_fec_ber, post_fec_ber)\n" \
"            end\n" \
"        end\n" \
"    end\n" \
"    fort.set_cell_prop(ftable, 1, fort.ANY_COLUMN, fort.CPROP_ROW_TYPE, fort.ROW_HEADER)\n" \
"    fort.set_cell_prop(ftable, fort.ANY_ROW, 4, fort.CPROP_TEXT_ALIGN, fort.ALIGNED_RIGHT)\n" \
"    fort.set_cell_prop(ftable, fort.ANY_ROW, 5, fort.CPROP_TEXT_ALIGN, fort.ALIGNED_RIGHT)\n" \
"    fort.set_cell_prop(ftable, fort.ANY_ROW, 6, fort.CPROP_TEXT_ALIGN, fort.ALIGNED_RIGHT)\n" \
"    print(ftable)\n" \
"end)\n" \
"\n" \
"slash.register_command({\"fecana\", \"histogram\"}, [[\n" \
"Get a PRBS fec analyzer histogram.\n" \
"\n" \
"This is an imperfect capture as we can only capture errors 4 at a time per lane. This means the error captures are from\n" \
"different periods of time.\n" \
"\n" \
"Arguments:\n" \
"\n" \
"    <lanes>          (lanelist default all)    lanes to capture errors\n" \
"    -d,--duration    (time default 1s)         how long to capture symbol errors per group\n" \
"    -p,--precise                               show full counters even if very large\n" \
"\n" \
"]], function(slice, argt)\n" \
"    ---@type integer[]\n" \
"    local lanes = argt.lanes\n" \
"\n" \
"    ---@type table<integer, integer[]>\n" \
"    local data = {}\n" \
"\n" \
"    ---@type integer[]\n" \
"    local fec_lanes = {}\n" \
"    for lane in iter(lanes) do\n" \
"        local mode = credo.lane_get_mode(slice, lane)\n" \
"        if not crutil.is_lane_configured(mode) then\n" \
"            goto continue\n" \
"        end\n" \
"        local enabled = credo.fecana_query(slice, lane)\n" \
"        if not enabled then\n" \
"            goto continue\n" \
"        end\n" \
"        list.append(fec_lanes, lane)\n" \
"        ::continue::\n" \
"    end\n" \
"\n" \
"    for group = 0, 3 do\n" \
"        for lane in iter(fec_lanes) do\n" \
"            credo.fecana_set_hist_group(slice, lane, group)\n" \
"        end\n" \
"        time.sleep(argt.duration)\n" \
"        for lane in iter(fec_lanes) do\n" \
"            local counters = credo.fecana_get_hist_counter(slice, lane)\n" \
"            if data[lane] == nil then\n" \
"                data[lane] = counters\n" \
"            else\n" \
"                list.extend(data[lane], counters)\n" \
"            end\n" \
"        end\n" \
"    end\n" \
"\n" \
"    local ftable = fort.create()\n" \
"\n" \
"    ftable:print(\"SEI\")\n" \
"    for lane in iter(lanes) do\n" \
"        ftable:print(\"%s(%02d)\" % {crutil.get_lane_id(slice, lane), lane})\n" \
"    end\n" \
"    ftable:ln()\n" \
"    ftable:add_separator()\n" \
"    for error_count = 0, 15 do\n" \
"        ftable:print(\">= %d\" % {error_count})\n" \
"        for lane in iter(lanes) do\n" \
"            if data[lane] == nil then\n" \
"                ftable:print(\"-\")\n" \
"                goto continue\n" \
"            end\n" \
"            local count = data[lane][error_count + 1]\n" \
"            if count > 1e6 and not argt.precise then\n" \
"                ftable:print(\"%.3g\" % {count})\n" \
"            else\n" \
"                ftable:print(\"%d\" % {count})\n" \
"            end\n" \
"            ::continue::\n" \
"        end\n" \
"        ftable:ln()\n" \
"    end\n" \
"\n" \
"    ftable:set_cell_prop(fort.ANY_ROW, fort.ANY_COLUMN, fort.CPROP_TEXT_ALIGN, fort.ALIGNED_RIGHT)\n" \
"    print(ftable)\n" \
"    print(\"Duration: %.1f sec\" % {argt.duration * 4})\n" \
"end)\n";
static const char lualib_commands_fw_code[] = "local slash = require \"slash\"\n" \
"local credo = require \"credo\"\n" \
"local fort = require \"fort\"\n" \
"local intmod = require \"int\"\n" \
"\n" \
"slash.register_command({\"fw\", \"version\"}, [[\n" \
"Display firmware version.\n" \
"\n" \
"]], function(slice, argt)\n" \
"    print(credo.firmware_version_str(slice), \"0x%X\" % {credo.firmware_hash(slice)})\n" \
"end)\n" \
"\n" \
"slash.register_command({\"fw\", \"status\"}, [[\n" \
"Display firmware status.\n" \
"\n" \
"]], function(slice, argt)\n" \
"    if credo.firmware_get_status(slice) == 1 then\n" \
"        print(\"Firmware: RUNNING\")\n" \
"    else\n" \
"        print(\"Firmware: NOT RUNNING\")\n" \
"    end\n" \
"end)\n" \
"\n" \
"slash.register_command({\"fw\", \"load\"}, [[\n" \
"Load firmware. (DEBUG)\n" \
"\n" \
"Prefer using `> slice reinit`\n" \
"\n" \
"Arguments:\n" \
"\n" \
"    -f,--force\n" \
"    <path>        (string)    firmware path\n" \
"\n" \
"]], function(slice, argt)\n" \
"    credo.firmware_load(slice, argt.path, argt.force)\n" \
"end)\n" \
"\n" \
"slash.register_command({\"fw\", \"unload\"}, [[\n" \
"Unload firmware. (DEBUG)\n" \
"\n" \
"]], function(slice, argt)\n" \
"    credo.firmware_unload(slice)\n" \
"end)\n" \
"\n" \
"slash.register_command({\"fw\", \"cmd\"}, [[\n" \
"Run a firmware command. (DEBUG)\n" \
"\n" \
"Arguments:\n" \
"\n" \
"    <command>    (integer)\n" \
"    <param>      (integer)\n" \
"\n" \
"]], function(slice, argt)\n" \
"    local response, response_param = credo.firmware_cmd(slice, argt.command, argt.param)\n" \
"    print(\"0x%X, 0x%X\" % {response, response_param})\n" \
"end)\n" \
"\n" \
"slash.register_command({\"fw\", \"cmdex\"}, [[\n" \
"Run a firmware command. (DEBUG)\n" \
"\n" \
"Arguments:\n" \
"\n" \
"    <command>    (integer)\n" \
"    <param1>     (integer)\n" \
"    <param2>     (integer)\n" \
"\n" \
"]], function(slice, argt)\n" \
"    local res, rparam1, rparam2 = credo.firmware_cmd_ex(slice, argt.command, argt.param1, argt.param2)\n" \
"    print(\"0x%X, 0x%X, 0x%X\" % {res, rparam1, rparam2})\n" \
"end)\n" \
"\n" \
"local function do_fw_debug_cmd(slice, argt, extra)\n" \
"    ---@type integer[]\n" \
"    local lane_list = argt.lane_list\n" \
"    ---@type integer\n" \
"    local section = argt.section\n" \
"    ---@type integer[]\n" \
"    local index_list = argt.index_list\n" \
"\n" \
"    local ftable = fort.create_table()\n" \
"    fort.set_cell_prop(ftable, fort.ANY_ROW, fort.ANY_COLUMN, fort.CPROP_TEXT_ALIGN, fort.ALIGNED_CENTER)\n" \
"    fort.set_cell_prop(ftable, fort.ANY_ROW, fort.ANY_COLUMN, fort.CPROP_LEFT_PADDING, 0)\n" \
"    fort.set_cell_prop(ftable, fort.ANY_ROW, fort.ANY_COLUMN, fort.CPROP_RIGHT_PADDING, 0)\n" \
"\n" \
"    local limits = credo.slice_get_limits(slice)\n" \
"    local num_lane = limits.max_lanes\n" \
"\n" \
"    -- fwdebug_header\n" \
"    fort.printf(ftable, \"index\")\n" \
"    for lane in iter(lane_list) do\n" \
"        if lane >= num_lane then\n" \
"            break\n" \
"        end\n" \
"        fort.printf(ftable, \"Ln%2d\", lane)\n" \
"    end\n" \
"    fort.ln(ftable)\n" \
"    fort.add_separator(ftable)\n" \
"\n" \
"    local api_func\n" \
"    if extra == true then\n" \
"        api_func = credo.firmware_debug_cmd_ex\n" \
"    else\n" \
"        api_func = credo.firmware_debug_cmd\n" \
"    end\n" \
"\n" \
"    for index in iter(index_list) do\n" \
"        fort.printf(ftable, \"%4d\", index)\n" \
"        for lane in iter(lane_list) do\n" \
"            if lane >= num_lane then\n" \
"                break\n" \
"            end\n" \
"            local ret, res, res1 = pcall(api_func, slice, lane, section, index)\n" \
"            if ret ~= true then\n" \
"                fort.printf(ftable, \" - \")\n" \
"            elseif res1 ~= nil then\n" \
"                fort.printf(ftable, \"%04X,%04X\", res, res1)\n" \
"            else\n" \
"                fort.printf(ftable, \"%04X\", res)\n" \
"            end\n" \
"        end\n" \
"        fort.ln(ftable)\n" \
"    end\n" \
"\n" \
"    print(\"section\", section)\n" \
"    print(fort.to_string(ftable))\n" \
"end\n" \
"\n" \
"slash.register_command({\"fw\", \"debug_cmd\"}, [[\n" \
"Run a firmware debug command. (DEBUG)\n" \
"\n" \
"Arguments:\n" \
"\n" \
"    <lane_list>     (lanelist)\n" \
"    <section>       (integer)\n" \
"    <index_list>    (intlist)\n" \
"\n" \
"]], function(slice, argt)\n" \
"    do_fw_debug_cmd(slice, argt, false)\n" \
"end)\n" \
"\n" \
"slash.register_command({\"fw\", \"debug_cmdex\"}, [[\n" \
"Run a firmware debug command. (DEBUG)\n" \
"\n" \
"Arguments:\n" \
"\n" \
"    <lane_list>     (lanelist)\n" \
"    <section>       (integer)\n" \
"    <index_list>    (intlist)\n" \
"\n" \
"]], function(slice, argt)\n" \
"    do_fw_debug_cmd(slice, argt, true)\n" \
"end)\n" \
"\n" \
"slash.register_command({\"fw\", \"reg\"}, [[\n" \
"Get/set firmware registers\n" \
"\n" \
"Arguments:\n" \
"\n" \
"    <addresses>     (intlist)\n" \
"    -v,--value      (optional integer)\n" \
"    -b,--bits       (optional regbits)\n" \
"    -s,--section    (optional integer)    extended registers\n" \
"]], function(slice, argt)\n" \
"\n" \
"    ---@type integer | nil\n" \
"    local section = argt.section\n" \
"    ---@type RegisterBits|nil\n" \
"    local bits = argt.bits\n" \
"\n" \
"    local function fw_regread(address)\n" \
"        if section ~= nil then\n" \
"            return credo.firmware_reg_rd_ex(slice, address, section)\n" \
"        else\n" \
"            return credo.firmware_reg_rd(slice, address)\n" \
"        end\n" \
"    end\n" \
"\n" \
"    if argt.value ~= nil then\n" \
"        ---@type integer\n" \
"        local value = argt.value\n" \
"        for address in iter(argt.addresses) do\n" \
"            local regvalue = value\n" \
"            if bits ~= nil then\n" \
"                local curvalue = fw_regread(address)\n" \
"                value = intmod.bitset(curvalue, regvalue, bits.msb, bits.lsb)\n" \
"            end\n" \
"\n" \
"            if section ~= nil then\n" \
"                credo.firmware_reg_wr_ex(slice, address, section, value)\n" \
"            else\n" \
"                credo.firmware_reg_wr(slice, address, value)\n" \
"            end\n" \
"        end\n" \
"    end\n" \
"\n" \
"    local ftable = fort.create_table()\n" \
"    if section ~= nil then\n" \
"        ftable:print_ln(\"Section %d\" % {section})\n" \
"    end\n" \
"    ftable:print_ln(\"Address|Value\")\n" \
"    ftable:add_separator()\n" \
"\n" \
"    for address in iter(argt.addresses) do\n" \
"        local regval = fw_regread(address)\n" \
"        if bits ~= nil then\n" \
"            regval = intmod.bitget(regval, bits.msb, bits.lsb)\n" \
"        end\n" \
"        local regbit_str = choose(bits ~= nil, \".\" .. tostring(bits), \"\")\n" \
"        ftable:print_ln(\"%s%s|%s\" % {hex(address), regbit_str, hex(regval)})\n" \
"    end\n" \
"    print(ftable)\n" \
"end)\n";
