static const char lualib_commands_nutcracker_opti_code[] = "local slash = require \"slash\"\n" \
"local credo = require \"credo\"\n" \
"local crutil = require \"crutil\"\n" \
"local fort = require \"fort\"\n" \
"local cjson = require \"cjson\"\n" \
"\n" \
"local opt_mode_map = {[0] = \"full\", [1] = \"bypass\", [2] = \"partial\"}\n" \
"local opt_mode_map_str = {full = 0, bypass = 1, partial = 2}\n" \
"\n" \
"slash.register_chip_command({\"opti\", \"info\"}, credo.FAMILY_NUTCRACKER, [[\n" \
"Display opti\n" \
"\n" \
"Arguments:\n" \
"\n" \
"    <lanes>      (lanelist default a*)    Lanes to display\n" \
"]], function(slice, argt)\n" \
"    ---@type integer[]\n" \
"    local lanes = argt.lanes\n" \
"\n" \
"    assert(math.max(table.unpack(lanes)) < 8, \"Only host lanes supported\")\n" \
"\n" \
"    local ftable = fort.create()\n" \
"    ftable:print_ln(\"Lane|Opti Mode\")\n" \
"    ftable:add_separator()\n" \
"\n" \
"    for lane in iter(lanes) do\n" \
"        ftable:print(\"%s (%2d)\" % {crutil.get_lane_id(slice, lane), lane})\n" \
"\n" \
"        local opti_mode = credo.lane_get_option(slice, lane, \"opti_mode\")\n" \
"        ftable:print_ln(\"%s\" % {opt_mode_map[opti_mode]})\n" \
"    end\n" \
"    print(ftable)\n" \
"end)\n" \
"\n" \
"slash.register_chip_command({\"opti\", \"capture\"}, credo.FAMILY_NUTCRACKER, [[\n" \
"Display prbs training information\n" \
"\n" \
"Arguments:\n" \
"\n" \
"    <lanes>      (lanelist default a*)  Lanes to capture\n" \
"    -f,--file    (optional file-out)    Store output to json file\n" \
"]], function(slices, argt)\n" \
"\n" \
"    ---@type integer[]\n" \
"    slices = slices\n" \
"\n" \
"    ---@type integer[]\n" \
"    local lanes = argt.lanes\n" \
"\n" \
"    assert(math.max(table.unpack(lanes)) < 8, \"Only host lanes supported\")\n" \
"\n" \
"    local data = {}\n" \
"\n" \
"    local ftable = fort.create()\n" \
"\n" \
"    ftable:print_ln(\"Slice|Opti Capture Data\")\n" \
"    ftable:print(\"\")\n" \
"    for lane in iter(argt.lanes) do\n" \
"        ftable:print(\"Ln %s (%2d)\" % {crutil.get_lane_id(slices[1], lane), lane})\n" \
"    end\n" \
"    ftable:ln()\n" \
"    ftable:add_separator()\n" \
"\n" \
"    local lane_count = #argt.lanes\n" \
"    if lane_count > 1 then\n" \
"        ftable:set_cell_span(1, 2, lane_count)\n" \
"    end\n" \
"\n" \
"    for slice in iter(slices) do\n" \
"        ftable:print(\"%d\" % {slice})\n" \
"        for lane in iter(argt.lanes) do\n" \
"            local lane_mode = credo.lane_get_mode(slice, lane)\n" \
"            if not crutil.is_lane_configured(lane_mode) then\n" \
"                ftable:print(\"OFF\")\n" \
"                goto continue\n" \
"            end\n" \
"            local status = credo.prbs_training_rx_get_status(slice, lane)\n" \
"            if status ~= credo.PRBS_TRAINING_LINKED then\n" \
"                ftable:print(\"PRBS Training not finished\")\n" \
"                goto continue\n" \
"            end\n" \
"            local lane_data = {\n" \
"                slice = slice,\n" \
"                lane = lane,\n" \
"                data = credo.data_capture(slice, \"opti_capture\", {lane = lane})\n" \
"            }\n" \
"            list.append(data, lane_data)\n" \
"            ftable:print(\"%s\" % {lane_data.data})\n" \
"            ::continue::\n" \
"        end\n" \
"        ftable:ln()\n" \
"        ftable:add_separator()\n" \
"    end\n" \
"\n" \
"    if argt.file == nil then\n" \
"        print(ftable)\n" \
"    else\n" \
"        local json_data = cjson.encode(data)\n" \
"        argt.file:write(json_data)\n" \
"    end\n" \
"\n" \
"end, slash.MULTISLICE)\n" \
"\n" \
"slash.register_chip_command({\"opti\", \"load\"}, credo.FAMILY_NUTCRACKER, [[\n" \
"Load optimization settings from json file.\n" \
"\n" \
"Arguments:\n" \
"\n" \
"    <file>       (file-in)     optimization load file\n" \
"    <lanes>      (lanelist)    Lanes to load\n" \
"    --opt       (full|bypass|partial default partial)    Specify opt mode\n" \
"]], function(slices, argt)\n" \
"\n" \
"    ---@type integer[]\n" \
"    slices = slices\n" \
"\n" \
"    ---@type integer[]\n" \
"    local lanes = argt.lanes\n" \
"\n" \
"    assert(math.max(table.unpack(lanes)) < 8, \"Only host lanes supported\")\n" \
"\n" \
"    local data_str = argt.file:read(\"*all\")\n" \
"    local full_data = cjson.decode(data_str)\n" \
"\n" \
"    local mapped_data = {}\n" \
"\n" \
"    for lane_data in iter(full_data) do\n" \
"        local slice = lane_data.slice\n" \
"        local lane = lane_data.lane\n" \
"        local data = lane_data.data\n" \
"\n" \
"        assert(type(slice) == \"number\", \"Invalid slice\")\n" \
"        assert(type(lane) == \"number\", \"Invalid lane\")\n" \
"        assert(type(data) == \"string\", \"Invalid data\")\n" \
"\n" \
"        if mapped_data[slice] == nil then\n" \
"            mapped_data[slice] = {}\n" \
"        end\n" \
"\n" \
"        mapped_data[slice][lane] = data\n" \
"\n" \
"    end\n" \
"\n" \
"    for slice in iter(slices) do\n" \
"        local slice_data = mapped_data[slice]\n" \
"        if slice_data == nil then\n" \
"            print(\"WARN: slice %d missing opti data. skipping.\" % {slice})\n" \
"            goto next_slice\n" \
"        end\n" \
"        for lane in iter(lanes) do\n" \
"            local lane_data = slice_data[lane]\n" \
"            if lane_data == nil then\n" \
"                print(\"WARN: slice %d, lane %d missing opti data. skipping.\")\n" \
"                goto next_lane\n" \
"            end\n" \
"            credo.lane_set_option(slice, lane, \"opti_mode\", opt_mode_map_str[argt.opt]) -- set to mode\n" \
"            credo.slice_load_setup(slice, lane_data .. \"\\n\")\n" \
"            ::next_lane::\n" \
"        end\n" \
"        ::next_slice::\n" \
"    end\n" \
"\n" \
"end, slash.MULTISLICE)\n";
static const char lualib_commands_nutcracker_phymode_code[] = "local slash = require \"slash\"\n" \
"local credo = require \"credo\"\n" \
"\n" \
"local opt_mode_map = {full = 0, bypass = 1, partial = 2}\n" \
"\n" \
"slash.register_chip_command({\"phymode\", \"config\"}, credo.FAMILY_NUTCRACKER, [[\n" \
"Configure lanes into phy mode\n" \
"\n" \
"Enabling AN or LT will cause the lane to transmit PRBS when the modes are finished.\n" \
"\n" \
"Arugments:\n" \
"\n" \
"    <lanes>      (lanelist)\n" \
"    <speed>      (speed)\n" \
"    -m,--mode    (optional lanemode)    Lane mode to use, if not set it will determine base on speed\n" \
"                                        (<50G means NRZ, otherwise PAM4)\n" \
"    --lt                                Enable Link Training on line side\n" \
"    --opt        (optional full|bypass|partial) Specify opt mode on host side\n" \
"]], function(slice, argt)\n" \
"    local mode = argt.mode\n" \
"    if mode == nil then\n" \
"        if argt.speed < 50000 then\n" \
"            mode = credo.LMODE_NRZ\n" \
"        else\n" \
"            mode = credo.LMODE_PAM4\n" \
"        end\n" \
"    end\n" \
"    for lane in iter(argt.lanes) do\n" \
"        local flags = 0\n" \
"        if lane >= 8 and argt.lt then\n" \
"            flags = flags | credo.LFLAG_LT\n" \
"        end\n" \
"        if lane < 8 and argt.opt ~= nil then\n" \
"            credo.lane_set_option(slice, lane, \"opti_mode\", opt_mode_map[argt.opt])\n" \
"        end\n" \
"        credo.phy_configure(slice, lane, mode, argt.speed, flags)\n" \
"    end\n" \
"end)\n" \
"\n" \
"slash.register_chip_command({\"phymode\", \"destroy\"}, credo.FAMILY_NUTCRACKER, [[\n" \
"Destroy phy mode for selected lanes.\n" \
"\n" \
"Arugments:\n" \
"\n" \
"    <lanes>    (lanelist)\n" \
"\n" \
"]], ---@param slice integer\n" \
"---@param argt {lanes: integer[]}\n" \
"function(slice, argt)\n" \
"    for lane in iter(argt.lanes) do\n" \
"        credo.phy_destroy(slice, lane)\n" \
"    end\n" \
"end)\n";
