"        fort.print(ftable, \"%2s(%02d)\" % {crutil.get_lane_id(slice, lane), lane})\n" \
"        fort.printf(ftable, \"%s\", choose(mode == credo.LMODE_NRZ, \"nrz\", \"pam4\"))\n" \
"        for isi_val in iter(isi) do\n" \
"            fort.printf(ftable, \"%d\", isi_val)\n" \
"        end\n" \
"        fort.ln(ftable)\n" \
"        ::end_loop::\n" \
"    end\n" \
"\n" \
"    fort.set_cell_prop(ftable, 2, fort.ANY_COLUMN, fort.CPROP_ROW_TYPE, fort.ROW_HEADER)\n" \
"    fort.set_cell_prop(ftable, fort.ANY_ROW, fort.ANY_COLUMN, fort.CPROP_TEXT_ALIGN, fort.ALIGNED_RIGHT)\n" \
"    print(fort.to_string(ftable))\n" \
"end)\n" \
"\n" \
"serdes.register_tx_taps(credo.FAMILY_NUTCRACKER, {\"pre3\", \"pre2\", \"pre1\", \"main\", \"post1\", \"post2\", \"post3\"})\n" \
"\n" \
"slash.register_chip_command({\"serdes\", \"tx_taps_nl\"}, credo.FAMILY_NUTCRACKER, [[\n" \
"Get/Set tx taps nonlinear\n" \
"\n" \
"Arguments:\n" \
"\n" \
"    <lanes>        (lanelist default all)        lanes to get set\n" \
"    -r,--reset                                   reset the taps to default settings\n" \
"    -f,--full      (optional intlist)            set all tx taps\n" \
"    -p,--partial   (optional intmap)             set select tx taps\n" \
"    -lv,--level    (optional intlist default 0,0,0,0)  set level, level_bar, level_3, level_bar_3\n" \
"\n" \
"Examples:\n" \
"\n" \
"    > /serdes tx_taps_nl                       # display all tx taps\n" \
"    > /serdes tx_taps_nl 0-7                   # display tx taps for 0-7 lanes\n" \
"    > /serdes tx_taps_nl a*                    # display tx taps for lanes on host side\n" \
"    > /serdes tx_taps_nl b*                    # display tx taps for lanes on line side\n" \
"    > /serdes tx_taps_nl -r                    # reset all tx taps\n" \
"    > /serdes tx_taps_nl -f 0,1,2,3,4,5,6,7    # set all tx taps for all lanes\n" \
"    > /serdes tx_taps_nl -p 1=3,3=112          # set partial tx taps for all lanes {1=3,3=112}\n" \
"\n" \
"]], function(slice, argt)\n" \
"\n" \
"    local lanes = argt.lanes\n" \
"    if argt.reset then\n" \
"        for lane in iter(lanes) do\n" \
"            credo.serdes_reset_tx_taps(slice, lane)\n" \
"        end\n" \
"        return\n" \
"    end\n" \
"    if argt.full ~= nil or argt.partial ~= nil then\n" \
"        local partial = argt.partial\n" \
"        if partial then\n" \
"            local count = credo.serdes_get_tx_ffe_range(slice, lanes[1])\n" \
"            local min, max = list.minmax(tablex.keys(partial))\n" \
"            -- print(\"partial:\", pairs(partial))\n" \
"            assert(min >= 0, \"Minimum partial key must be >= 0\")\n" \
"            assert(max < count, \"Maximum partial must be < %d\" % {count})\n" \
"        end\n" \
"        for lane in iter(lanes) do\n" \
"            local val\n" \
"            if argt.full then\n" \
"                val = {table.unpack(argt.full)}\n" \
"            else\n" \
"                val = credo.serdes_get_tx_taps(slice, lane)\n" \
"            end\n" \
"            if partial then\n" \
"                for index, tap in pairs(partial) do\n" \
"                    val[index + 1] = tap\n" \
"                end\n" \
"            end\n" \
"            for v in iter(argt.level) do\n" \
"                table.insert(val, v)\n" \
"            end\n" \
"            if lane < 8 then\n" \
"                print(\"lane %d set tx_taps_nl {%d,%d,%d,%d} {%d,%d,%d,%d}\" % {lane, table.unpack(val)})\n" \
"            else\n" \
"                print(\"lane %d set tx_taps_nl {%d,%d,%d,%d,%d,%d,%d} {%d,%d,%d,%d}\" % {lane, table.unpack(val)})\n" \
"            end\n" \
"            credo.serdes_set_param(slice, 'tx_taps_nl', lane, val)\n" \
"        end\n" \
"        return\n" \
"    end\n" \
"\n" \
"    local function get_table_range(tbl, si, ei)\n" \
"        local new_tbl = {}\n" \
"        for i = si, ei do\n" \
"            table.insert(new_tbl, tbl[i])\n" \
"        end\n" \
"        return new_tbl\n" \
"    end\n" \
"\n" \
"    local ncreg = require\"regmap\".slice(slice)\n" \
"    local ftablea = fort.create_table()\n" \
"    local ftableb = fort.create_table()\n" \
"    fort.write_ln(ftablea, \"\", \"auto\", \"Taps\", \"\", \"\", \"Taps_bar\", \"\", \"\", \"Taps_3\", \"\", \"\", \"Taps_bar_3\", \"\", \"\")\n" \
"    fort.write_ln(ftablea, \"Lane\", \"select\", \"-1 M +1 +2\", \"Scale\", \"Sum\", \"-1 M +1 +2\", \"Scale\", \"Sum\", \"-1 M +1 +2\",\n" \
"                  \"Scale\", \"Sum\", \"-1 M +1 +2\", \"Scale\", \"Sum\")\n" \
"    fort.add_separator(ftablea)\n" \
"    local is_host = false\n" \
"    local is_line = false\n" \
"    for lane in iter(argt.lanes) do\n" \
"        if lane >= 8 then\n" \
"            goto continue\n" \
"        end\n" \
"        is_host = true\n" \
"        local taps = credo.serdes_get_param(slice, 'tx_taps_nl', lane)\n" \
"        fort.printf(ftablea, \"%s(%d)\", crutil.get_lane_id(slice, lane), lane)\n" \
"        local auto_sel = \"\"\n" \
"        auto_sel = auto_sel .. ncreg.pam100_v.reg_tx_coef_4_auto_sel:read(slice, lane)\n" \
"        auto_sel = auto_sel .. ncreg.pam100_v.reg_tx_coef_3_auto_sel:read(slice, lane)\n" \
"        auto_sel = auto_sel .. ncreg.pam100_v.reg_tx_coef_2_auto_sel:read(slice, lane)\n" \
"        auto_sel = auto_sel .. ncreg.pam100_v.reg_tx_coef_1_auto_sel:read(slice, lane)\n" \
"        fort.printf(ftablea, \"%s\" % {auto_sel})\n" \
"        local pr1, m, po1, po2, scale, sum = table.unpack(get_table_range(taps, 1, 6))\n" \
"        fort.printf(ftablea, \"%d  %d  %d  %d\" % {pr1, m, po1, po2})\n" \
"        fort.printf(ftablea, \"%d|%d\" % {scale, sum})\n" \
"        pr1, m, po1, po2, scale, sum = table.unpack(get_table_range(taps, 7, 12))\n" \
"        fort.printf(ftablea, \"%d  %d  %d  %d\" % {pr1, m, po1, po2})\n" \
"        fort.printf(ftablea, \"%d|%d\" % {scale, sum})\n" \
"        pr1, m, po1, po2, scale, sum = table.unpack(get_table_range(taps, 13, 18))\n" \
"        fort.printf(ftablea, \"%d  %d  %d  %d\" % {pr1, m, po1, po2})\n" \
"        fort.printf(ftablea, \"%d|%d\" % {scale, sum})\n" \
"        pr1, m, po1, po2, scale, sum = table.unpack(get_table_range(taps, 19, 24))\n" \
"        fort.printf(ftablea, \"%d  %d  %d  %d\" % {pr1, m, po1, po2})\n" \
"        fort.printf(ftablea, \"%d|%d\" % {scale, sum})\n" \
"        fort.ln(ftablea)\n" \
"        ::continue::\n" \
"    end\n" \
"    if is_host then\n" \
"        print(ftablea)\n" \
"    end\n" \
"    fort.write_ln(ftableb, \"\", \"auto\", \"Taps\", \"\", \"Taps_bar\", \"\", \"Taps_3\", \"\", \"Taps_bar_3\", \"\")\n" \
"    fort.write_ln(ftableb, \"Lane\", \"select\", \"-3 -2 -1 M +1 +2 +3\", \"Sum\", \"-3 -2 -1 M +1 +2 +3\", \"Sum\",\n" \
"                  \"-3 -2 -1 M +1 +2 +3\", \"Sum\", \"-3 -2 -1 M +1 +2 +3\", \"Sum\")\n" \
"    fort.add_separator(ftableb)\n" \
"    for lane in iter(argt.lanes) do\n" \
"        if lane < 8 then\n" \
"            goto continue\n" \
"        end\n" \
"        is_line = true\n" \
"        local taps = credo.serdes_get_param(slice, 'tx_taps_nl', lane)\n" \
"        fort.printf(ftableb, \"%s(%d)\", crutil.get_lane_id(slice, lane), lane)\n" \
"        local auto_sel = \"\"\n" \
"        auto_sel = auto_sel .. ncreg.pam100.reg_tx_coef_auto_sel_m3:read(slice, lane - 8)\n" \
"        auto_sel = auto_sel .. ncreg.pam100.reg_tx_coef_auto_sel_m2:read(slice, lane - 8)\n" \
"        auto_sel = auto_sel .. ncreg.pam100.reg_tx_coef_auto_sel_m1:read(slice, lane - 8)\n" \
"        auto_sel = auto_sel .. ncreg.pam100.reg_tx_coef_auto_sel_0:read(slice, lane - 8)\n" \
"        auto_sel = auto_sel .. ncreg.pam100.reg_tx_coef_auto_sel_1:read(slice, lane - 8)\n" \
"        auto_sel = auto_sel .. ncreg.pam100.reg_tx_coef_auto_sel_2:read(slice, lane - 8)\n" \
"        auto_sel = auto_sel .. ncreg.pam100.reg_tx_coef_auto_sel_3:read(slice, lane - 8)\n" \
"        fort.printf(ftableb, \"%s\" % {auto_sel})\n" \
"        local pr3, pr2, pr1, m, po1, po2, po3, sum = table.unpack(taps, 1, 8)\n" \
"        fort.printf(ftableb, \"%d  %d  %d  %d  %d  %d  %d|%d\" % {pr3, pr2, pr1, m, po1, po2, po3, sum})\n" \
"        pr3, pr2, pr1, m, po1, po2, po3, sum = table.unpack(taps, 9, 16)\n" \
"        fort.printf(ftableb, \"%d  %d  %d  %d  %d  %d  %d|%d\" % {pr3, pr2, pr1, m, po1, po2, po3, sum})\n" \
"        pr3, pr2, pr1, m, po1, po2, po3, sum = table.unpack(taps, 17, 24)\n" \
"        fort.printf(ftableb, \"%d  %d  %d  %d  %d  %d  %d|%d\" % {pr3, pr2, pr1, m, po1, po2, po3, sum})\n" \
"        pr3, pr2, pr1, m, po1, po2, po3, sum = table.unpack(taps, 25, 32)\n" \
"        fort.printf(ftableb, \"%d  %d  %d  %d  %d  %d  %d|%d\" % {pr3, pr2, pr1, m, po1, po2, po3, sum})\n" \
"        fort.ln(ftableb)\n" \
"        ::continue::\n" \
"    end\n" \
"    if is_line then\n" \
"        print(ftableb)\n" \
"    end\n" \
"end)\n" \
"\n" \
"slash.register_chip_command({\"serdes\", \"tx_6taps\"}, credo.FAMILY_NUTCRACKER, [[\n" \
"Get/Set tx 6-taps\n" \
"\n" \
"Arguments:\n" \
"\n" \
"    <lanes>        (lanelist default all)        lanes to get set\n" \
"    -f,--full      (optional intlist)            set all tx taps\n" \
"    -p,--partial   (optional intmap)             set select tx taps\n" \
"    -s,--scale     (optional integer default 1)  set full scale\n" \
"\n" \
"Examples:\n" \
"\n" \
"    > /serdes tx_6taps                       # display all tx taps\n" \
"    > /serdes tx_6taps 0-7                   # display tx taps for 0-7 lanes\n" \
"    > /serdes tx_6taps a*                    # display tx taps for lanes on host side\n" \
"    > /serdes tx_6taps -f 0,1,2,3,4,5        # set all tx taps for all lanes\n" \
"    > /serdes tx_6taps -p 1=3,3=112          # set partial tx taps for all lanes {1=3,3=112}\n" \
"\n" \
"]], function(slice, argt)\n" \
"    local lanes = argt.lanes\n" \
"\n" \
"    local function get_table_range(tbl, si, ei)\n" \
"        local new_tbl = {}\n" \
"        for i = si, ei do\n" \
"            table.insert(new_tbl, tbl[i])\n" \
"        end\n" \
"        return new_tbl\n" \
"    end\n" \
"\n" \
"    if argt.full ~= nil or argt.partial ~= nil then\n" \
"        local partial = argt.partial\n" \
"        if partial then\n" \
"            local count = 6\n" \
"            local min, max = list.minmax(tablex.keys(partial))\n" \
"            -- print(\"partial:\", pairs(partial))\n" \
"            assert(min >= 0, \"Minimum partial key must be >= 0\")\n" \
"            assert(max < count, \"Maximum partial must be < %d\" % {count})\n" \
"        end\n" \
"        for lane in iter(lanes) do\n" \
"            if lane >= 8 then\n" \
"                goto continue\n" \
"            end\n" \
"            local val\n" \
"            if argt.full then\n" \
"                val = {table.unpack(argt.full)}\n" \
"            else\n" \
"                val = get_table_range(credo.serdes_get_param(slice, 'tx_6taps', lane), 1, 6)\n" \
"            end\n" \
"            if partial then\n" \
"                for index, tap in pairs(partial) do\n" \
"                    val[index + 1] = tap\n" \
"                end\n" \
"            end\n" \
"            local scale_str = choose(argt.scale == 1, \"full\", \"half\")\n" \
"            print(\"lane %d set tx_6taps %s-scale {%d,%d,%d,%d,%d,%d}\" % {lane, scale_str, table.unpack(val)})\n" \
"            table.insert(val, argt.scale)\n" \
"            credo.serdes_set_param(slice, 'tx_6taps', lane, val)\n" \
"            ::continue::\n" \
"        end\n" \
"        return\n" \
"    end\n" \
"\n" \
"    local regmap = require\"regmap\".slice(slice)\n" \
"    local ftable = fort.create_table()\n" \
"    fort.write_ln(ftable, \"\", \"auto\", \"6-Taps NRZ\", \"\")\n" \
"    fort.write_ln(ftable, \"Lane\", \"select\", \"-1 M +1 +2 +3 +4\", \"Scale\")\n" \
"    fort.add_separator(ftable)\n" \
"    for lane in iter(argt.lanes) do\n" \
"        if lane >= 8 then\n" \
"            goto continue\n" \
"        end\n" \
"        fort.printf(ftable, \"%s(%d)\", crutil.get_lane_id(slice, lane), lane)\n" \
"        local auto_sel = \"\"\n" \
"        auto_sel = auto_sel .. regmap.nrz50_v.reg_tx_coef_4_auto_sel:read(slice, lane)\n" \
"        auto_sel = auto_sel .. regmap.nrz50_v.reg_tx_coef_3_auto_sel:read(slice, lane)\n" \
"        auto_sel = auto_sel .. regmap.nrz50_v.reg_tx_coef_2_auto_sel:read(slice, lane)\n" \
"        auto_sel = auto_sel .. regmap.nrz50_v.reg_tx_coef_1_auto_sel:read(slice, lane)\n" \
"        fort.printf(ftable, \"%s\" % {auto_sel})\n" \
"        local pr1, m, po1, po2, po3, po4, scale = table.unpack(credo.serdes_get_param(slice, 'tx_6taps', lane))\n" \
"        fort.printf(ftable, \"%d  %d  %d  %d  %d  %d\" % {pr1, m, po1, po2, po3, po4})\n" \
"        local scale_str = choose(scale == 1, \"full\", \"half\")\n" \
"        fort.printf(ftable, \"%s-scale\" % {scale_str})\n" \
"        fort.ln(ftable)\n" \
"        ::continue::\n" \
"    end\n" \
"    print(ftable)\n" \
"end)\n";
