static const char lualib_commands_osprey_prbs_code[] = "local slash = require \"slash\"\n" \
"local credo = require \"credo\"\n" \
"\n" \
"slash.register_chip_command({\"prbs\", \"monitor\"}, credo.FAMILY_OSPREY, [[\n" \
"Display prbs rx_monitor information\n" \
"\n" \
"Can also be used to initialize the monitor. This includes\n" \
"- Configuring prbs fec analyzer (if not set)\n" \
"- Clearing fec analyzer counter and timer\n" \
"- Clearing prbs counter and timer\n" \
"\n" \
"Arguments:\n" \
"\n" \
"    -i,--init                              Perform initialization\n" \
"    -t,--time    (optional time)           Switch from global time to a window time\n" \
"    <lanes>      (lanelist default all)    Lanes to display / initialize\n" \
"\n" \
"Examples:\n" \
"\n" \
"    > prbs monitor            # display prbs monitor all lanes global time\n" \
"    > prbs monitor 0-7        # display prbs monitor certain lanes global time\n" \
"    > prbs monitor -i         # init monitor all lanes\n" \
"    > prbs monitor -i 0-7     # init monitor certain lanes\n" \
"    > prbs monitor -t 1.5s    # display prbs monitor all lanes for a 1.5sec window\n" \
"\n" \
"\n" \
"]], function(slice, argt)\n" \
"    local command = \"rx_monitor \"\n" \
"    if argt.init then\n" \
"        command = command .. \"init\"\n" \
"    end\n" \
"\n" \
"    command = command .. \" \" .. list.join(argt.lanes, \",\")\n" \
"\n" \
"    if not argt.init and argt.time ~= nil then\n" \
"        command = command .. \" %d\" % {argt.time * 1000}\n" \
"    end\n" \
"\n" \
"    credo.display_info_print(slice, command)\n" \
"end)\n";
static const char lualib_commands_osprey_rsfec_code[] = "local slash = require \"slash\"\n" \
"local credo = require \"credo\"\n" \
"local fort = require \"fort\"\n" \
"\n" \
"slash.register_chip_command({\"rsfec\", \"histogram\"}, credo.FAMILY_OSPREY, [[\n" \
"Display rsfec counter histogram.\n" \
"\n" \
"Arguments:\n" \
"\n" \
"    <ports>          (portlist default all)    ports to capture histogram\n" \
"    -c,--clear                                 clear the histogram\n" \
"\n" \
"]], function(slice, argt)\n" \
"\n" \
"    local ftable = fort.new()\n" \
"    ftable:write(\"Symbol\")\n" \
"\n" \
"    ---@type table<integer, credo.PortConfig>\n" \
"    local port_configs = {}\n" \
"\n" \
"    for port_id in iter(argt.ports) do\n" \
"        local port_config = credo.port_query(slice, port_id)\n" \
"        if port_id ~= port_config.port_id then\n" \
"            goto end_loop\n" \
"        end\n" \
"        port_configs[port_id] = port_config\n" \
"        ftable:write(\"Port %d\" % {port_id}, \"\")\n" \
"\n" \
"        if argt.clear then\n" \
"            credo.rsfec_reset_count(slice, port_id, credo.SIDE_HOST)\n" \
"            credo.rsfec_reset_count(slice, port_id, credo.SIDE_LINE)\n" \
"        end\n" \
"\n" \
"        ::end_loop::\n" \
"    end\n" \
"\n" \
"    -- skip printing anything on clear command\n" \
"    if argt.clear then\n" \
"        return\n" \
"    end\n" \
"\n" \
"    ftable:ln()\n" \
"    ftable:write(\"Bin\")\n" \
"    for port_id in iter(argt.ports) do\n" \
"        local port_config = port_configs[port_id]\n" \
"        if port_config == nil then\n" \
"            goto end_loop\n" \
"        end\n" \
"        ftable:write(\"host (A)\", \"line (B)\")\n" \
"        ::end_loop::\n" \
"    end\n" \
"    ftable:ln()\n" \
"    ftable:add_separator()\n" \
"    for hist_bin = 0, 15 do\n" \
"        ftable:print(\">= %d\" % {hist_bin})\n" \
"        for port_id in iter(argt.ports) do\n" \
"            local port_config = port_configs[port_id]\n" \
"            if port_config == nil then\n" \
"                goto end_loop\n" \
"            end\n" \
"            local hist_val_a = credo.rsfec_get_histogram(slice, port_id, credo.SIDE_HOST, hist_bin)\n" \
"            if hist_val_a > 9e6 then\n" \
"                ftable:print(\"%.3g\" % {hist_val_a})\n" \
"            else\n" \
"                ftable:print(\"%d\" % {hist_val_a})\n" \
"            end\n" \
"\n" \
"            if port_config.line_fec_type ~= credo.FEC_NONE then\n" \
"                local hist_val_b = credo.rsfec_get_histogram(slice, port_id, credo.SIDE_LINE, hist_bin)\n" \
"                ftable:print(\"%d\" % {hist_val_b})\n" \
"            else\n" \
"                ftable:print(\"-\")\n" \
"            end\n" \
"            ::end_loop::\n" \
"        end\n" \
"        ftable:ln()\n" \
"    end\n" \
"\n" \
"    -- make the port id span 2 columns\n" \
"    for col = 1, ftable:col_count() // 2 do\n" \
"        ftable:set_cell_span(1, col * 2, 2)\n" \
"    end\n" \
"    ftable:set_cell_prop(fort.ANY_ROW, fort.ANY_COLUMN, fort.CPROP_TEXT_ALIGN, fort.ALIGNED_RIGHT)\n" \
"    print(ftable)\n" \
"end)\n" \
"\n" \
"slash.register_chip_command({\"rsfec\", \"monitor\"}, credo.FAMILY_OSPREY, [[\n" \
"Display rsfec counter and error rates.\n" \
"\n" \
"Given that the counters are clear on read, the error rates can only be properly\n" \
"computed when a duration is provided. Therefore we only show error rate values\n" \
"when a duration is specified\n" \
"\n" \
"Arguments:\n" \
"\n" \
"    <ports>          (portlist default all)    List of ports to access\n" \
"    -d,--duration    (optional time)           Capture over a period of time\n" \
"]], function(slice, argt)\n" \
"\n" \
"    assert(argt.duration == nil or argt.duration > 0, \"Duration must be > 0ms\")\n" \
"\n" \
"    ---@type table<integer,credo.PortConfig>\n" \
"    local port_configs = {}\n" \
"    for port_id in iter(argt.ports) do\n" \
"        local port_config = credo.port_query(slice, port_id)\n" \
"\n" \
"        if port_id ~= port_config.port_id then\n" \
"            goto end_loop\n" \
"        end\n" \
"\n" \
"        port_configs[port_id] = port_config\n" \
"\n" \
"        if argt.duration ~= nil then\n" \
"            credo.rsfec_reset_count(slice, port_id, credo.SIDE_HOST)\n" \
"            credo.rsfec_reset_count(slice, port_id, credo.SIDE_LINE)\n" \
"        end\n" \
"\n" \
"        ::end_loop::\n" \
"    end\n" \
"\n" \
"    if argt.duration ~= nil then\n" \
"        time.sleep(argt.duration)\n" \
"    end\n" \
"\n" \
"    local ftable = fort.new()\n" \
"    ftable:write_ln(\"Port\", \"Dir\", \"Align\", \"Correctable CW\", \"Uncorrectable CW\", \"Total\", \"Correctable\")\n" \
"    ftable:write_ln(\"\", \"\", \"FEC PCS\", \"Errors\", \"Errors\", \"Codewords\", \"Error Rate\")\n" \
"    ftable:add_separator()\n" \
"\n" \
"    for port_id, port_config in pairs(port_configs) do\n" \
"        local align_a = credo.rsfec_get_align_status(slice, port_id, credo.SIDE_HOST)\n" \
"        local corr_err_a = credo.rsfec_get_corrected_codeword(slice, port_id, credo.SIDE_HOST)\n" \
"        local uncorr_err_a = credo.rsfec_get_uncorrected_codeword(slice, port_id, credo.SIDE_HOST)\n" \
"        local total_cw_a = credo.rsfec_get_total_codeword(slice, port_id, credo.SIDE_HOST)\n" \
"\n" \
"        local align_b = credo.rsfec_get_align_status(slice, port_id, credo.SIDE_LINE)\n" \
"        local corr_err_b = credo.rsfec_get_corrected_codeword(slice, port_id, credo.SIDE_LINE)\n" \
"        local uncorr_err_b = credo.rsfec_get_uncorrected_codeword(slice, port_id, credo.SIDE_LINE)\n" \
"        local total_cw_b = credo.rsfec_get_total_codeword(slice, port_id, credo.SIDE_LINE)\n" \
"\n" \
"        ftable:print(\"%d|A->B|%3s %3s\" %\n" \
"                         {port_id, choose(align_a.fec_aligned, \"yes\", \"no\"), choose(align_a.pcs_aligned, \"yes\", \"no\")})\n" \
"        ftable:print(\"%d|%d\" % {corr_err_a, uncorr_err_a})\n" \
"        ftable:print(\"%.3g\" % {total_cw_a})\n" \
"        if total_cw_a > 0 then\n" \
"            ftable:print(\"%.3g\" % {corr_err_a / total_cw_a})\n" \
"        else\n" \
"            ftable:print(\"-\")\n" \
"        end\n" \
"        ftable:ln()\n" \
"\n" \
"        ftable:print(\"|B->A|%3s %3s\" %\n" \
"                         {choose(align_b.fec_aligned, \"yes\", \"no\"), choose(align_a.pcs_aligned, \"yes\", \"no\")})\n" \
"\n" \
"        local lfec_en = true\n" \
"        ftable:print(choose(lfec_en, \"%d|%d\" % {corr_err_b, uncorr_err_b}, \"-|-\"))\n" \
"        ftable:print(\"%.3g\" % {total_cw_b})\n" \
"        if total_cw_b > 0 then\n" \
"            ftable:print(\"%.3g\" % {corr_err_b / total_cw_b})\n" \
"        else\n" \
"            ftable:print(\"-\")\n" \
"        end\n" \
"        ftable:ln()\n" \
"        ftable:add_separator()\n" \
"    end\n" \
"    ftable:set_cell_prop(fort.ANY_ROW, fort.ANY_COLUMN, fort.CPROP_TEXT_ALIGN, fort.ALIGNED_RIGHT)\n" \
"    print(ftable)\n" \
"end)\n" \
"\n" \
"slash.register_chip_command({\"rsfec\", \"clear\"}, credo.FAMILY_OSPREY, [[\n" \
"Clear rsfec counters.\n" \
"\n" \
"Arguments:\n" \
"\n" \
"    <ports>    (portlist)    ports to clear rsfec counters\n" \
"\n" \
"]], function(slice, argt)\n" \
"\n" \
"    for port_id in iter(argt.ports) do\n" \
"        local port_config = credo.port_query(slice, port_id)\n" \
"        if port_config.port_id == credo.PORT_UNCONFIGURED then\n" \
"            goto end_loop\n" \
"        end\n" \
"\n" \
"        credo.rsfec_reset_count(slice, port_id, credo.SIDE_HOST)\n" \
"        credo.rsfec_reset_count(slice, port_id, credo.SIDE_LINE)\n" \
"\n" \
"        ::end_loop::\n" \
"    end\n" \
"end)\n";
static const char lualib_commands_osprey_serdes_code[] = "local slash = require \"slash\"\n" \
"local credo = require \"credo\"\n" \
"local fort = require \"fort\"\n" \
"local crutil = require \"crutil\"\n" \
"\n" \
"local serdes = require \"commands.common.serdes\"\n" \
"\n" \
"slash.register_chip_command({\"serdes\", \"isi\"}, credo.FAMILY_OSPREY, [[\n" \
"Display isi table.\n" \
"\n" \
"Arguments:\n" \
"\n" \
"    <lanes>    (lanelist default all)\n" \
"\n" \
"]], function(slice, argt)\n" \
"    local ftable = fort.create_table()\n" \
"\n" \
"    fort.printf_ln(ftable, \"isi|nrz|fm1|f4|f5|f6|f7|f8|f9|f10|f11|f12|f13|f14|f15|f16|f17|f18\")\n" \
"    fort.printf_ln(ftable, \"lane|pam4|fm3|fm2|fm1|f2|f3|f4|f5|f6|f7|f8|f9|f10|f11|f12|f13|f14\")\n" \
"\n" \
"    ---@type integer\n" \
"    for lane in iter(argt.lanes) do\n" \
"        local mode = credo.lane_get_mode(slice, lane)\n" \
"        if not crutil.is_lane_configured(mode) then\n" \
"            fort.printf_ln(ftable, \"%d|-\", lane)\n" \
"            goto end_loop\n" \
"        end\n" \
"        local isi = credo.serdes_get_param(slice, \"rx_isi\", lane)\n" \
"        fort.printf(ftable, \"%d\", lane)\n" \
"        fort.printf(ftable, \"%s\", choose(mode == credo.LMODE_NRZ, \"nrz\", \"pam4\"))\n" \
"        for isi_val in iter(isi) do\n" \
"            fort.printf(ftable, \"%d\", isi_val)\n" \
"        end\n" \
"        fort.ln(ftable)\n" \
"        ::end_loop::\n" \
"    end\n" \
"\n" \
"    fort.set_cell_prop(ftable, 2, fort.ANY_COLUMN, fort.CPROP_ROW_TYPE, fort.ROW_HEADER)\n" \
"    fort.set_cell_prop(ftable, fort.ANY_ROW, fort.ANY_COLUMN, fort.CPROP_TEXT_ALIGN, fort.ALIGNED_RIGHT)\n" \
"    print(fort.to_string(ftable))\n" \
"end)\n" \
"\n" \
"slash.register_chip_command({\"serdes\", \"param\"}, credo.FAMILY_OSPREY, [[\n" \
"Display serdes paramter table.\n" \
"\n" \
"Arguments:\n" \
"\n" \
"    <lanes>    (lanelist default all)\n" \
"\n" \
"Example:\n" \
"\n" \
"    > serdes param           # dispaly all lanes\n" \
"    > serdes param 0-2       # select lanes\n" \
"\n" \
"]], function(slice, argt)\n" \
"    local command = \"serdes_param \"\n" \
"    credo.display_info_print(slice, \"%s%s\" % {command, list.join(argt.lanes, \",\")})\n" \
"end)\n" \
"\n" \
"slash.register_chip_command({\"serdes\", \"control\"}, credo.FAMILY_OSPREY, [[\n" \
"Display serdes control table.\n" \
"\n" \
"]], function(slice, argt)\n" \
"    credo.display_info_print(slice, \"serdes_control\")\n" \
"end)\n" \
"\n" \
"serdes.register_tx_taps(credo.FAMILY_OSPREY, {\"pre3\", \"pre2\", \"pre1\", \"main\", \"post1\", \"post2\", \"post3\"})\n";
