"-- internal tools\n" \
"\n" \
"---@param slice integer\n" \
"---@return table<string, integer[]>\n" \
"function credo.reghive_get_map(slice)\n" \
"    local count = _credo.cri_slice_get_reghive_count(slice)\n" \
"    local reghives = {}\n" \
"    for i = 0, count - 1 do\n" \
"        local reghive = _credo.CrIntlRegHive_t()\n" \
"        local data = {}\n" \
"\n" \
"        _credo.cri_slice_index_reghive(slice, i, reghive)\n" \
"        for idx = 0, reghive.count - 1 do\n" \
"            local addr = _credo.cri_slice_get_addr(slice, idx, reghive, 0)\n" \
"            list.append(data, addr)\n" \
"        end\n" \
"\n" \
"        reghives[string.lower(reghive.hivename)] = data\n" \
"    end\n" \
"    return reghives\n" \
"end\n" \
"\n" \
"--- Make all structs with enum types use them and have nice luaish bindings\n" \
"do\n" \
"    local struct = require \"struct\"\n" \
"\n" \
"    struct.enum(credo.PortConfig, \"flags\", credo.PortFlags)\n" \
"    struct.enum(credo.PortConfig, \"port_type\", credo.PortType)\n" \
"    struct.enum(credo.PortConfig, \"port_mode\", credo.PortMode)\n" \
"    struct.enum(credo.PortConfig, \"host_fec_type\", credo.FecType)\n" \
"    struct.enum(credo.PortConfig, \"line_fec_type\", credo.FecType)\n" \
"    struct.enum(credo.PortConfig, \"port_id\", credo.PortID)\n" \
"\n" \
"    struct.enum(credo.PortSetup, \"mode\", credo.PortType)\n" \
"\n" \
"    struct.enum(credo.FecAnalyzerConfig, \"error_type\", credo.FecErrorType)\n" \
"    struct.enum(credo.Param, \"val_type\", credo.ParamValue)\n" \
"    struct.enum(credo.Param, \"index_type\", credo.ParamIndex)\n" \
"\n" \
"    struct.enum(credo.PacketInjectConfig, \"mode\", credo.PacketInjectMode, true)\n" \
"    struct.enum(credo.ChannelDesc, \"mode\", credo.LaneMode)\n" \
"    struct.enum(credo.RegVerifyConfig, \"flags\", credo.RegVerifyFlags)\n" \
"    struct.set_struct_tostrings(credo)\n" \
"end\n" \
"\n" \
"return credo\n";
static const char lualib_crs_code[] = "local _crs = require \"_crs\"\n" \
"\n" \
"---@classmod crs\n" \
"---@overload fun (...:string): any\n" \
"local crs = {}\n" \
"\n" \
"---@diagnostic disable-next-line: param-type-mismatch\n" \
"setmetatable(crs, crs)\n" \
"\n" \
"---@function crs:__call\n" \
"---Run crs command\n" \
"---@vararg string\n" \
"---@return any\n" \
"function crs:__call(...)\n" \
"    local varargs = {...}\n" \
"    assert(#varargs > 0, \"Must provide a command\")\n" \
"    if type(varargs[1]) == \"string\" then\n" \
"        local commands = list.split(varargs[1])\n" \
"        varargs = list.extend(commands, tablex.sub(varargs, 2))\n" \
"    end\n" \
"\n" \
"    local command = tablex.reduce(function(a, h)\n" \
"        if type(h) == \"string\" then\n" \
"            return a .. \"'%s', \" % {h}\n" \
"        elseif type(h) == \"number\" then\n" \
"            if types.is_integer(h) then\n" \
"                return a .. \"%d, \" % {h}\n" \
"            else\n" \
"                return a .. \"%f, \" % {h}\n" \
"            end\n" \
"        else\n" \
"            error(\"Invalid item\")\n" \
"        end\n" \
"        return a .. tostring(h)\n" \
"    end, varargs, \"\")\n" \
"    command = \"crs(%s)\" % {string.sub(command, 1, -3)}\n" \
"    _crs.run_command(command)\n" \
"\n" \
"    local output_count = _crs.get_output_count()\n" \
"    if output_count == 0 then\n" \
"        return\n" \
"    end\n" \
"\n" \
"    local retval = {}\n" \
"    for index = 0, output_count - 1 do\n" \
"        local subcount = _crs.get_output_subcount(index)\n" \
"        list.append(retval, {})\n" \
"        for subi = 0, subcount - 1 do\n" \
"            local value = _crs.get_output_item(index, subi)\n" \
"            local num_value = tonumber(value)\n" \
"            if num_value ~= nil then\n" \
"                value = num_value\n" \
"            end\n" \
"            list.append(retval[index + 1], value)\n" \
"        end\n" \
"        if subcount == 1 then\n" \
"            retval[index + 1] = retval[index + 1][1]\n" \
"        end\n" \
"    end\n" \
"    if output_count == 1 then\n" \
"        retval = retval[1]\n" \
"    end\n" \
"    return retval\n" \
"end\n" \
"\n" \
"return crs\n";
static const char lualib_crutil_code[] = "---@module 'crutil'\n" \
"local crutil = {}\n" \
"\n" \
"function crutil.is_lane_configured(mode)\n" \
"    return not list.contains({credo.LMODE_DISABLE, credo.LMODE_OFF}, mode)\n" \
"end\n" \
"\n" \
"---allow users to select all lanes by sides for lanelist\n" \
"---@param slice integer\n" \
"---@param side \"a\"|\"b\"\n" \
"---@return integer[]\n" \
"function crutil.get_side_lanelist(slice, side)\n" \
"\n" \
"    local device_type = credo.slice_get_device_type(slice)\n" \
"\n" \
"    -- special cases with disabled lanes\n" \
"    if list.contains({credo.DEV_OSPREY_800, credo.DEV_OWL_800}, device_type) then\n" \
"        return choose(side == \"a\", range(0, 7), range(12, 19))\n" \
"    end\n" \
"    -- heron has a side and b side switched\n" \
"    if list.contains({credo.DEV_HERON_1P0, credo.DEV_HERON_MR}, device_type) then\n" \
"        return choose(side == \"a\", range(8, 15), range(0, 7))\n" \
"    end\n" \
"    if list.contains({credo.DEV_SPARROW_800}, device_type) then\n" \
"        return choose(side == \"a\", range(0, 1), range(2, 5))\n" \
"    end\n" \
"    -- default case\n" \
"    local host_count, line_count = credo.lane_get_count(slice)\n" \
"    return choose(side == \"a\", range(0, host_count - 1), range(host_count, host_count + line_count - 1))\n" \
"end\n" \
"\n" \
"---@param slice integer\n" \
"---@param lane integer\n" \
"---@param safe? boolean  gives '-' on invalid id instead of error. Default true.\n" \
"---@return string\n" \
"function crutil.get_lane_id(slice, lane, safe)\n" \
"    if safe == nil then\n" \
"        safe = true\n" \
"    end\n" \
"    local alanes = crutil.get_side_lanelist(slice, \"a\")\n" \
"    local blanes = crutil.get_side_lanelist(slice, \"b\")\n" \
"\n" \
"    local id = list.index(alanes, lane)\n" \
"    if id ~= nil then\n" \
"        return \"A%d\" % {id - 1}\n" \
"    end\n" \
"    id = list.index(blanes, lane)\n" \
"\n" \
"    if id ~= nil then\n" \
"        return \"B%d\" % {id - 1}\n" \
"    end\n" \
"    assert(safe, \"Invalid lane for identifier %d\" % {lane})\n" \
"    return \"--\"\n" \
"end\n" \
"\n" \
"function crutil.twos_to_int(twos, width)\n" \
"    local mask = 1 << (width - 1)\n" \
"    return (twos & (~mask)) - (twos & mask)\n" \
"end\n" \
"\n" \
"function crutil.int_to_twos(value, width)\n" \
"    return ((1 << width) + value) & ((1 << width) - 1);\n" \
"end\n" \
"\n" \
"return crutil\n";
