"  testLireSymbole(math.AdditionTest)\n" \
"\n" \
"Tests run: 2, Failures: 1, Errors: 0, Skipped: 0\n" \
"\n" \
"\n" \
"-- LuaUnit\n" \
"---- non verbose\n" \
"* display . or F or E when running tests\n" \
"---- verbose\n" \
"* display test name + ok/fail\n" \
"----\n" \
"* blank line\n" \
"* number) ERROR or FAILURE: TestName\n" \
"   Stack trace\n" \
"* blank line\n" \
"* number) ERROR or FAILURE: TestName\n" \
"   Stack trace\n" \
"\n" \
"then --------------\n" \
"then \"Ran x tests in 0.000s (%d not selected, %d skipped)\"\n" \
"then OK or FAILED (failures=1, error=1)\n" \
"\n" \
"\n" \
"]]\n" \
"\n" \
"local TextOutput = genericOutput.new() -- derived class\n" \
"local TextOutput_MT = {__index = TextOutput} -- metatable\n" \
"TextOutput.__class__ = 'TextOutput'\n" \
"\n" \
"function TextOutput.new(runner)\n" \
"    local t = genericOutput.new(runner, M.VERBOSITY_DEFAULT)\n" \
"    t.errorList = {}\n" \
"    return setmetatable(t, TextOutput_MT)\n" \
"end\n" \
"\n" \
"function TextOutput:startSuite()\n" \
"    if self.verbosity > M.VERBOSITY_DEFAULT then\n" \
"        print('Started on ' .. self.result.startDate)\n" \
"    end\n" \
"end\n" \
"\n" \
"function TextOutput:startTest(testName)\n" \
"    if self.verbosity > M.VERBOSITY_DEFAULT then\n" \
"        io.stdout:write(\"    \", self.result.currentNode.testName, \" ... \")\n" \
"    end\n" \
"end\n" \
"\n" \
"function TextOutput:endTest(node)\n" \
"    if node:isSuccess() then\n" \
"        if self.verbosity > M.VERBOSITY_DEFAULT then\n" \
"            io.stdout:write(\"Ok\\n\")\n" \
"        else\n" \
"            io.stdout:write(\".\")\n" \
"            io.stdout:flush()\n" \
"        end\n" \
"    else\n" \
"        if self.verbosity > M.VERBOSITY_DEFAULT then\n" \
"            print(node.status)\n" \
"            print(node.msg)\n" \
"            --[[\n" \
"                -- find out when to do this:\n" \
"                if self.verbosity > M.VERBOSITY_DEFAULT then\n" \
"                    print( node.stackTrace )\n" \
"                end\n" \
"                ]]\n" \
"        else\n" \
"            -- write only the first character of status E, F or S\n" \
"            io.stdout:write(string.sub(node.status, 1, 1))\n" \
"            io.stdout:flush()\n" \
"        end\n" \
"    end\n" \
"end\n" \
"\n" \
"function TextOutput:displayOneFailedTest(index, fail)\n" \
"    print(index .. \") \" .. fail.testName)\n" \
"    print(fail.msg)\n" \
"    print(fail.stackTrace)\n" \
"    print()\n" \
"end\n" \
"\n" \
"function TextOutput:displayErroredTests()\n" \
"    if #self.result.errorTests ~= 0 then\n" \
"        print(\"Tests with errors:\")\n" \
"        print(\"------------------\")\n" \
"        for i, v in ipairs(self.result.errorTests) do\n" \
"            self:displayOneFailedTest(i, v)\n" \
"        end\n" \
"    end\n" \
"end\n" \
"\n" \
"function TextOutput:displayFailedTests()\n" \
"    if #self.result.failedTests ~= 0 then\n" \
"        print(\"Failed tests:\")\n" \
"        print(\"-------------\")\n" \
"        for i, v in ipairs(self.result.failedTests) do\n" \
"            self:displayOneFailedTest(i, v)\n" \
"        end\n" \
"    end\n" \
"end\n" \
"\n" \
"function TextOutput:endSuite()\n" \
"    if self.verbosity > M.VERBOSITY_DEFAULT then\n" \
"        print(\"=========================================================\")\n" \
"    else\n" \
"        print()\n" \
"    end\n" \
"    self:displayErroredTests()\n" \
"    self:displayFailedTests()\n" \
"    print(M.LuaUnit.statusLine(self.result))\n" \
"    if self.result.notSuccessCount == 0 then\n" \
"        print('OK')\n" \
"    end\n" \
"end\n" \
"\n" \
"-- class TextOutput end\n" \
"\n" \
"----------------------------------------------------------------\n" \
"--                     class NilOutput\n" \
"----------------------------------------------------------------\n" \
"\n" \
"local function nopCallable()\n" \
"    -- print(42)\n" \
"    return nopCallable\n" \
"end\n" \
"\n" \
"local NilOutput = {__class__ = 'NilOuptut'} -- class\n" \
"local NilOutput_MT = {__index = nopCallable} -- metatable\n" \
"\n" \
"function NilOutput.new(runner)\n" \
"    return setmetatable({__class__ = 'NilOutput'}, NilOutput_MT)\n" \
"end\n" \
"\n" \
"----------------------------------------------------------------\n" \
"--\n" \
"--                     class LuaUnit\n" \
"--\n" \
"----------------------------------------------------------------\n" \
"\n" \
"M.LuaUnit = {outputType = TextOutput, verbosity = M.VERBOSITY_DEFAULT, __class__ = 'LuaUnit', instances = {}}\n" \
"local LuaUnit_MT = {__index = M.LuaUnit}\n" \
"\n" \
"if EXPORT_ASSERT_TO_GLOBALS then\n" \
"    LuaUnit = M.LuaUnit\n" \
"end\n" \
"\n" \
"function M.LuaUnit.new()\n" \
"    local newInstance = setmetatable({}, LuaUnit_MT)\n" \
"    return newInstance\n" \
"end\n" \
"\n" \
"-----------------[[ Utility methods ]]---------------------\n" \
"\n" \
"function M.LuaUnit.asFunction(aObject)\n" \
"    -- return \"aObject\" if it is a function, and nil otherwise\n" \
"    if 'function' == type(aObject) then\n" \
"        return aObject\n" \
"    end\n" \
"end\n" \
"\n" \
"function M.LuaUnit.splitClassMethod(someName)\n" \
"    --[[\n" \
"        Return a pair of className, methodName strings for a name in the form\n" \
"        \"class.method\". If no class part (or separator) is found, will return\n" \
"        nil, someName instead (the latter being unchanged).\n" \
"\n" \
"        This convention thus also replaces the older isClassMethod() test:\n" \
"        You just have to check for a non-nil className (return) value.\n" \
"        ]]\n" \
"    local separator = string.find(someName, '.', 1, true)\n" \
"    if separator then\n" \
"        return someName:sub(1, separator - 1), someName:sub(separator + 1)\n" \
"    end\n" \
"    return nil, someName\n" \
"end\n" \
"\n" \
"function M.LuaUnit.isMethodTestName(s)\n" \
"    -- return true is the name matches the name of a test method\n" \
"    -- default rule is that is starts with 'Test' or with 'test'\n" \
"    return string.sub(s, 1, 4):lower() == 'test'\n" \
"end\n" \
"\n" \
"function M.LuaUnit.isTestName(s)\n" \
"    -- return true is the name matches the name of a test\n" \
"    -- default rule is that is starts with 'Test' or with 'test'\n" \
"    return string.sub(s, 1, 4):lower() == 'test'\n" \
"end\n" \
"\n" \
"function M.LuaUnit.collectTests()\n" \
"    -- return a list of all test names in the global namespace\n" \
"    -- that match LuaUnit.isTestName\n" \
"\n" \
"    local testNames = {}\n" \
"    for k, _ in pairs(_G) do\n" \
"        if type(k) == \"string\" and M.LuaUnit.isTestName(k) then\n" \
"            table.insert(testNames, k)\n" \
"        end\n" \
"    end\n" \
"    table.sort(testNames)\n" \
"    return testNames\n" \
"end\n" \
"\n" \
"function M.LuaUnit.parseCmdLine(cmdLine)\n" \
"    -- parse the command line\n" \
"    -- Supported command line parameters:\n" \
"    -- --verbose, -v: increase verbosity\n" \
"    -- --quiet, -q: silence output\n" \
"    -- --error, -e: treat errors as fatal (quit program)\n" \
"    -- --output, -o, + name: select output type\n" \
"    -- --pattern, -p, + pattern: run test matching pattern, may be repeated\n" \
"    -- --exclude, -x, + pattern: run test not matching pattern, may be repeated\n" \
"    -- --shuffle, -s, : shuffle tests before reunning them\n" \
"    -- --name, -n, + fname: name of output file for junit, default to stdout\n" \
"    -- --repeat, -r, + num: number of times to execute each test\n" \
"    -- [testnames, ...]: run selected test names\n" \
"    --\n" \
"    -- Returns a table with the following fields:\n" \
"    -- verbosity: nil, M.VERBOSITY_DEFAULT, M.VERBOSITY_QUIET, M.VERBOSITY_VERBOSE\n" \
"    -- output: nil, 'tap', 'junit', 'text', 'nil'\n" \
"    -- testNames: nil or a list of test names to run\n" \
"    -- exeRepeat: num or 1\n" \
"    -- pattern: nil or a list of patterns\n" \
"    -- exclude: nil or a list of patterns\n" \
"\n" \
"    local result, state = {}, nil\n" \
"    local SET_OUTPUT = 1\n" \
"    local SET_PATTERN = 2\n" \
"    local SET_EXCLUDE = 3\n" \
"    local SET_FNAME = 4\n" \
"    local SET_REPEAT = 5\n" \
"\n" \
"    if cmdLine == nil then\n" \
"        return result\n" \
"    end\n" \
"\n" \
"    local function parseOption(option)\n" \
"        if option == '--help' or option == '-h' then\n" \
"            result['help'] = true\n" \
"            return\n" \
"        elseif option == '--version' then\n" \
"            result['version'] = true\n" \
"            return\n" \
"        elseif option == '--verbose' or option == '-v' then\n" \
"            result['verbosity'] = M.VERBOSITY_VERBOSE\n" \
"            return\n" \
"        elseif option == '--quiet' or option == '-q' then\n" \
"            result['verbosity'] = M.VERBOSITY_QUIET\n" \
"            return\n" \
"        elseif option == '--error' or option == '-e' then\n" \
"            result['quitOnError'] = true\n" \
"            return\n" \
"        elseif option == '--failure' or option == '-f' then\n" \
"            result['quitOnFailure'] = true\n" \
"            return\n" \
"        elseif option == '--shuffle' or option == '-s' then\n" \
"            result['shuffle'] = true\n" \
"            return\n" \
"        elseif option == '--output' or option == '-o' then\n" \
"            state = SET_OUTPUT\n" \
"            return state\n" \
"        elseif option == '--name' or option == '-n' then\n" \
"            state = SET_FNAME\n" \
"            return state\n" \
"        elseif option == '--repeat' or option == '-r' then\n" \
"            state = SET_REPEAT\n" \
"            return state\n" \
"        elseif option == '--pattern' or option == '-p' then\n" \
"            state = SET_PATTERN\n" \
"            return state\n" \
"        elseif option == '--exclude' or option == '-x' then\n" \
"            state = SET_EXCLUDE\n" \
"            return state\n" \
"        end\n" \
"        error('Unknown option: ' .. option, 3)\n" \
"    end\n" \
"\n" \
"    local function setArg(cmdArg, state)\n" \
"        if state == SET_OUTPUT then\n" \
"            result['output'] = cmdArg\n" \
"            return\n" \
"        elseif state == SET_FNAME then\n" \
"            result['fname'] = cmdArg\n" \
"            return\n" \
"        elseif state == SET_REPEAT then\n" \
"            result['exeRepeat'] = tonumber(cmdArg) or error('Malformed -r argument: ' .. cmdArg)\n" \
"            return\n" \
"        elseif state == SET_PATTERN then\n" \
"            if result['pattern'] then\n" \
"                table.insert(result['pattern'], cmdArg)\n" \
"            else\n" \
"                result['pattern'] = {cmdArg}\n" \
"            end\n" \
"            return\n" \
"        elseif state == SET_EXCLUDE then\n" \
"            local notArg = '!' .. cmdArg\n" \
"            if result['pattern'] then\n" \
"                table.insert(result['pattern'], notArg)\n" \
"            else\n" \
"                result['pattern'] = {notArg}\n" \
"            end\n" \
"            return\n" \
"        end\n" \
"        error('Unknown parse state: ' .. state)\n" \
"    end\n" \
"\n" \
"    for i, cmdArg in ipairs(cmdLine) do\n" \
"        if state ~= nil then\n" \
"            setArg(cmdArg, state, result)\n" \
"            state = nil\n" \
"        else\n" \
"            if cmdArg:sub(1, 1) == '-' then\n" \
"                state = parseOption(cmdArg)\n" \
"            else\n" \
"                if result['testNames'] then\n" \
"                    table.insert(result['testNames'], cmdArg)\n" \
"                else\n" \
"                    result['testNames'] = {cmdArg}\n" \
"                end\n" \
"            end\n" \
"        end\n" \
"    end\n" \
"\n" \
"    if result['help'] then\n" \
"        M.LuaUnit.help()\n" \
"    end\n" \
"\n" \
"    if result['version'] then\n" \
"        M.LuaUnit.version()\n" \
"    end\n" \
"\n" \
"    if state ~= nil then\n" \
"        error('Missing argument after ' .. cmdLine[#cmdLine], 2)\n" \
"    end\n" \
"\n" \
"    return result\n" \
"end\n" \
"\n" \
"function M.LuaUnit.help()\n" \
"    print(M.USAGE)\n" \
"    os.exit(0, false, 0xDEAD)\n" \
"end\n" \
"\n" \
"function M.LuaUnit.version()\n" \
"    print('LuaUnit v' .. M.VERSION .. ' by Philippe Fremy <phil@freehackers.org>')\n" \
"    os.exit(0, false, 0xDEAD)\n" \
"end\n" \
"\n" \
"----------------------------------------------------------------\n" \
"--                     class NodeStatus\n" \
"----------------------------------------------------------------\n" \
"\n" \
"local NodeStatus = {__class__ = 'NodeStatus'} -- class\n" \
"local NodeStatus_MT = {__index = NodeStatus} -- metatable\n" \
"M.NodeStatus = NodeStatus\n" \
"\n" \
"-- values of status\n" \
"NodeStatus.SUCCESS = 'SUCCESS'\n" \
"NodeStatus.SKIP = 'SKIP'\n" \
"NodeStatus.FAIL = 'FAIL'\n" \
"NodeStatus.ERROR = 'ERROR'\n" \
"\n" \
"function NodeStatus.new(number, testName, className)\n" \
"    -- default constructor, test are PASS by default\n" \
"    local t = {number = number, testName = testName, className = className}\n" \
"    setmetatable(t, NodeStatus_MT)\n" \
"    t:success()\n" \
"    return t\n" \
"end\n" \
"\n" \
"function NodeStatus:success()\n" \
"    self.status = self.SUCCESS\n" \
"    -- useless because lua does this for us, but it helps me remembering the relevant field names\n" \
"    self.msg = nil\n" \
"    self.stackTrace = nil\n" \
"end\n" \
"\n" \
"function NodeStatus:skip(msg)\n" \
"    self.status = self.SKIP\n" \
"    self.msg = msg\n" \
"    self.stackTrace = nil\n" \
"end\n" \
"\n" \
"function NodeStatus:fail(msg, stackTrace)\n" \
"    self.status = self.FAIL\n" \
"    self.msg = msg\n" \
"    self.stackTrace = stackTrace\n" \
"end\n" \
"\n" \
"function NodeStatus:error(msg, stackTrace)\n" \
"    self.status = self.ERROR\n" \
"    self.msg = msg\n" \
"    self.stackTrace = stackTrace\n" \
"end\n" \
"\n" \
"function NodeStatus:isSuccess()\n" \
"    return self.status == NodeStatus.SUCCESS\n" \
"end\n" \
"\n" \
"function NodeStatus:isNotSuccess()\n" \
"    -- Return true if node is either failure or error or skip\n" \
"    return (self.status == NodeStatus.FAIL or self.status == NodeStatus.ERROR or self.status == NodeStatus.SKIP)\n" \
"end\n" \
"\n" \
"function NodeStatus:isSkipped()\n" \
"    return self.status == NodeStatus.SKIP\n" \
"end\n" \
"\n" \
"function NodeStatus:isFailure()\n" \
"    return self.status == NodeStatus.FAIL\n" \
"end\n" \
"\n" \
"function NodeStatus:isError()\n" \
"    return self.status == NodeStatus.ERROR\n" \
"end\n" \
"\n" \
"function NodeStatus:statusXML()\n" \
"    if self:isError() then\n" \
"        return table.concat({\n" \
"            '            <error type=\"', xmlEscape(self.msg), '\">\\n', '                <![CDATA[',\n" \
"            xmlCDataEscape(self.stackTrace), ']]></error>\\n'\n" \
"        })\n" \
"    elseif self:isFailure() then\n" \
"        return table.concat({\n" \
"            '            <failure type=\"', xmlEscape(self.msg), '\">\\n', '                <![CDATA[',\n" \
"            xmlCDataEscape(self.stackTrace), ']]></failure>\\n'\n" \
"        })\n" \
"    elseif self:isSkipped() then\n" \
"        return table.concat({'            <skipped>', xmlEscape(self.msg), '</skipped>\\n'})\n" \
"    end\n" \
"    return '            <passed/>\\n' -- (not XSD-compliant! normally shouldn't get here)\n" \
"end\n" \
"\n" \
"--------------[[ Output methods ]]-------------------------\n" \
"\n" \
"local function conditional_plural(number, singular)\n" \
"    -- returns a grammatically well-formed string \"%d <singular/plural>\"\n" \
"    local suffix = ''\n" \
"    if number ~= 1 then -- use plural\n" \
"        suffix = (singular:sub(-2) == 'ss') and 'es' or 's'\n" \
"    end\n" \
"    return string.format('%d %s%s', number, singular, suffix)\n" \
"end\n" \
"\n" \
"function M.LuaUnit.statusLine(result)\n" \
"    -- return status line string according to results\n" \
"    local s = {\n" \
"        string.format('Ran %d tests in %0.3f seconds', result.runCount, result.duration),\n" \
"        conditional_plural(result.successCount, 'success')\n" \
"    }\n" \
"    if result.notSuccessCount > 0 then\n" \
"        if result.failureCount > 0 then\n" \
"            table.insert(s, conditional_plural(result.failureCount, 'failure'))\n" \
"        end\n" \
"        if result.errorCount > 0 then\n" \
"            table.insert(s, conditional_plural(result.errorCount, 'error'))\n" \
"        end\n" \
"    else\n" \
"        table.insert(s, '0 failures')\n" \
"    end\n" \
"    if result.skippedCount > 0 then\n" \
"        table.insert(s, string.format(\"%d skipped\", result.skippedCount))\n" \
"    end\n" \
"    if result.nonSelectedCount > 0 then\n" \
"        table.insert(s, string.format(\"%d non-selected\", result.nonSelectedCount))\n" \
"    end\n" \
"    return table.concat(s, ', ')\n" \
"end\n" \
"\n" \
"function M.LuaUnit:startSuite(selectedCount, nonSelectedCount)\n" \
"    self.result = {\n" \
"        selectedCount = selectedCount,\n" \
"        nonSelectedCount = nonSelectedCount,\n" \
"        successCount = 0,\n" \
"        runCount = 0,\n" \
"        currentTestNumber = 0,\n" \
"        currentClassName = \"\",\n" \
"        currentNode = nil,\n" \
"        suiteStarted = true,\n" \
"        startTime = os.clock(),\n" \
"        startDate = os.date(os.getenv('LUAUNIT_DATEFMT')),\n" \
"        startIsodate = os.date('%Y-%m-%dT%H:%M:%S'),\n" \
"        patternIncludeFilter = self.patternIncludeFilter,\n" \
"\n" \
"        -- list of test node status\n" \
"        allTests = {},\n" \
"        failedTests = {},\n" \
"        errorTests = {},\n" \
"        skippedTests = {},\n" \
"\n" \
"        failureCount = 0,\n" \
"        errorCount = 0,\n" \
"        notSuccessCount = 0,\n" \
"        skippedCount = 0\n" \
"    }\n" \
"\n" \
"    self.outputType = self.outputType or TextOutput\n" \
"    self.output = self.outputType.new(self)\n" \
"    self.output:startSuite()\n" \
"end\n" \
"\n" \
"function M.LuaUnit:startClass(className, classInstance)\n" \
"    self.result.currentClassName = className\n" \
"    self.output:startClass(className)\n" \
"    self:setupClass(className, classInstance)\n" \
"end\n" \
"\n" \
"function M.LuaUnit:startTest(testName)\n" \
"    self.result.currentTestNumber = self.result.currentTestNumber + 1\n" \
"    self.result.runCount = self.result.runCount + 1\n" \
"    self.result.currentNode = NodeStatus.new(self.result.currentTestNumber, testName, self.result.currentClassName)\n" \
"    self.result.currentNode.startTime = os.clock()\n" \
"    table.insert(self.result.allTests, self.result.currentNode)\n" \
"    self.output:startTest(testName)\n" \
"end\n" \
"\n" \
"function M.LuaUnit:updateStatus(err)\n" \
"    -- \"err\" is expected to be a table / result from protectedCall()\n" \
"    if err.status == NodeStatus.SUCCESS then\n" \
"        return\n" \
"    end\n" \
"\n" \
"    local node = self.result.currentNode\n" \
"\n" \
"    --[[ As a first approach, we will report only one error or one failure for one test.\n" \
"\n" \
"        However, we can have the case where the test is in failure, and the teardown is in error.\n" \
"        In such case, it's a good idea to report both a failure and an error in the test suite. This is\n" \
"        what Python unittest does for example. However, it mixes up counts so need to be handled carefully: for\n" \
"        example, there could be more (failures + errors) count that tests. What happens to the current node ?\n" \
"\n" \
"        We will do this more intelligent version later.\n" \
"        ]]\n" \
"\n" \
"    -- if the node is already in failure/error, just don't report the new error (see above)\n" \
"    if node.status ~= NodeStatus.SUCCESS then\n" \
"        return\n" \
"    end\n" \
"\n" \
"    if err.status == NodeStatus.FAIL then\n" \
"        node:fail(err.msg, err.trace)\n" \
"        table.insert(self.result.failedTests, node)\n" \
"    elseif err.status == NodeStatus.ERROR then\n" \
"        node:error(err.msg, err.trace)\n" \
"        table.insert(self.result.errorTests, node)\n" \
"    elseif err.status == NodeStatus.SKIP then\n" \
"        node:skip(err.msg)\n" \
"        table.insert(self.result.skippedTests, node)\n" \
"    else\n" \
"        error('No such status: ' .. prettystr(err.status))\n" \
"    end\n" \
"\n" \
"    self.output:updateStatus(node)\n" \
"end\n" \
"\n" \
"function M.LuaUnit:endTest()\n" \
"    local node = self.result.currentNode\n" \
"    -- print( 'endTest() '..prettystr(node))\n" \
"    -- print( 'endTest() '..prettystr(node:isNotSuccess()))\n" \
"    node.duration = os.clock() - node.startTime\n" \
"    node.startTime = nil\n" \
"    self.output:endTest(node)\n" \
"\n" \
"    if node:isSuccess() then\n" \
"        self.result.successCount = self.result.successCount + 1\n" \
"    elseif node:isError() then\n" \
"        if self.quitOnError or self.quitOnFailure then\n" \
"            -- Runtime error - abort test execution as requested by\n" \
"            -- \"--error\" option. This is done by setting a special\n" \
"            -- flag that gets handled in internalRunSuiteByInstances().\n" \
"            print(\"\\nERROR during LuaUnit test execution:\\n\" .. node.msg)\n" \
"            self.result.aborted = true\n" \
"        end\n" \
"    elseif node:isFailure() then\n" \
"        if self.quitOnFailure then\n" \
"            -- Failure - abort test execution as requested by\n" \
"            -- \"--failure\" option. This is done by setting a special\n" \
"            -- flag that gets handled in internalRunSuiteByInstances().\n" \
"            print(\"\\nFailure during LuaUnit test execution:\\n\" .. node.msg)\n" \
"            self.result.aborted = true\n" \
"        end\n" \
"    elseif node:isSkipped() then\n" \
"        self.result.runCount = self.result.runCount - 1\n" \
"    else\n" \
"        error('No such node status: ' .. prettystr(node.status))\n" \
"    end\n" \
"    self.result.currentNode = nil\n" \
"end\n" \
"\n" \
"function M.LuaUnit:endClass()\n" \
"    self:teardownClass(self.lastClassName, self.lastClassInstance)\n" \
"    self.output:endClass()\n" \
"end\n" \
"\n" \
"function M.LuaUnit:endSuite()\n" \
"    if self.result.suiteStarted == false then\n" \
"        error('LuaUnit:endSuite() -- suite was already ended')\n" \
"    end\n" \
"    self.result.duration = os.clock() - self.result.startTime\n" \
"    self.result.suiteStarted = false\n" \
"\n" \
"    -- Expose test counts for outputter's endSuite(). This could be managed\n" \
"    -- internally instead by using the length of the lists of failed tests\n" \
"    -- but unit tests rely on these fields being present.\n" \
"    self.result.failureCount = #self.result.failedTests\n" \
"    self.result.errorCount = #self.result.errorTests\n" \
"    self.result.notSuccessCount = self.result.failureCount + self.result.errorCount\n" \
"    self.result.skippedCount = #self.result.skippedTests\n" \
"\n" \
"    self.output:endSuite()\n" \
"end\n" \
"\n" \
"function M.LuaUnit:setOutputType(outputType, fname)\n" \
"    -- Configures LuaUnit runner output\n" \
"    -- outputType is one of: NIL, TAP, JUNIT, TEXT\n" \
"    -- when outputType is junit, the additional argument fname is used to set the name of junit output file\n" \
"    -- for other formats, fname is ignored\n" \
"    if outputType:upper() == \"NIL\" then\n" \
"        self.outputType = NilOutput\n" \
"        return\n" \
"    end\n" \
"    if outputType:upper() == \"TAP\" then\n" \
"        self.outputType = TapOutput\n" \
"        return\n" \
"    end\n" \
"    if outputType:upper() == \"JUNIT\" then\n" \
"        self.outputType = JUnitOutput\n" \
"        if fname then\n" \
"            self.fname = fname\n" \
"        end\n" \
"        return\n" \
"    end\n" \
"    if outputType:upper() == \"TEXT\" then\n" \
"        self.outputType = TextOutput\n" \
"        return\n" \
"    end\n" \
"    error('No such format: ' .. outputType, 2)\n" \
"end\n" \
"\n" \
"--------------[[ Runner ]]-----------------\n" \
"\n" \
"function M.LuaUnit:protectedCall(classInstance, methodInstance, prettyFuncName)\n" \
"    -- if classInstance is nil, this is just a function call\n" \
"    -- else, it's method of a class being called.\n" \
"\n" \
"    local function err_handler(e)\n" \
"        -- transform error into a table, adding the traceback information\n" \
"        return {status = NodeStatus.ERROR, msg = e, trace = string.sub(debug.traceback(\"\", 1), 2)}\n" \
"    end\n" \
"\n" \
"    local ok, err\n" \
"    if classInstance then\n" \
"        -- stupid Lua < 5.2 does not allow xpcall with arguments so let's use a workaround\n" \
"        ok, err = xpcall(function()\n" \
"            methodInstance(classInstance)\n" \
"        end, err_handler)\n" \
"    else\n" \
"        ok, err = xpcall(function()\n" \
"            methodInstance()\n" \
"        end, err_handler)\n" \
"    end\n" \
"    if ok then\n" \
"        return {status = NodeStatus.SUCCESS}\n" \
"    end\n" \
"    -- print('ok=\"'..prettystr(ok)..'\" err=\"'..prettystr(err)..'\"')\n" \
"\n" \
"    local iter_msg\n" \
"    iter_msg = self.exeRepeat and 'iteration ' .. self.currentCount\n" \
"\n" \
"    err.msg, err.status = M.adjust_err_msg_with_iter(err.msg, iter_msg)\n" \
"\n" \
"    if err.status == NodeStatus.SUCCESS or err.status == NodeStatus.SKIP then\n" \
"        err.trace = nil\n" \
"        return err\n" \
"    end\n" \
"\n" \
"    -- reformat / improve the stack trace\n" \
"    if prettyFuncName then -- we do have the real method name\n" \
"        err.trace = err.trace:gsub(\"in (%a+) 'methodInstance'\", \"in %1 '\" .. prettyFuncName .. \"'\")\n" \
"    end\n" \
"    if STRIP_LUAUNIT_FROM_STACKTRACE then\n" \
"        err.trace = stripLuaunitTrace2(err.trace, err.msg)\n" \
"    end\n" \
"\n" \
"    return err -- return the error \"object\" (table)\n" \
"end\n" \
"\n" \
"function M.LuaUnit:execOneFunction(className, methodName, classInstance, methodInstance)\n" \
"    -- When executing a test function, className and classInstance must be nil\n" \
"    -- When executing a class method, all parameters must be set\n" \
"\n" \
"    if type(methodInstance) ~= 'function' then\n" \
"        self:unregisterSuite()\n" \
"        error(tostring(methodName) .. ' must be a function, not ' .. type(methodInstance))\n" \
"    end\n" \
"\n" \
"    local prettyFuncName\n" \
"    if className == nil then\n" \
"        className = '[TestFunctions]'\n" \
"        prettyFuncName = methodName\n" \
"    else\n" \
"        prettyFuncName = className .. '.' .. methodName\n" \
"    end\n" \
"\n" \
"    if self.lastClassName ~= className then\n" \
"        if self.lastClassName ~= nil then\n" \
"            self:endClass()\n" \
"        end\n" \
"        self:startClass(className, classInstance)\n" \
"        self.lastClassName = className\n" \
"        self.lastClassInstance = classInstance\n" \
"    end\n" \
"\n" \
"    self:startTest(prettyFuncName)\n" \
"\n" \
"    local node = self.result.currentNode\n" \
"    for iter_n = 1, self.exeRepeat or 1 do\n" \
"        if node:isNotSuccess() then\n" \
"            break\n" \
"        end\n" \
"        self.currentCount = iter_n\n" \
"\n" \
"        -- run setUp first (if any)\n" \
"        if classInstance then\n" \
"            local func = self.asFunction(classInstance.setUp) or self.asFunction(classInstance.Setup) or\n" \
"                             self.asFunction(classInstance.setup) or self.asFunction(classInstance.SetUp)\n" \
"            if func then\n" \
"                self:updateStatus(self:protectedCall(classInstance, func, className .. '.setUp'))\n" \
"            end\n" \
"        end\n" \
"\n" \
"        -- run testMethod()\n" \
"        if node:isSuccess() then\n" \
"            self:updateStatus(self:protectedCall(classInstance, methodInstance, prettyFuncName))\n" \
"        end\n" \
"\n" \
"        -- lastly, run tearDown (if any)\n" \
"        if classInstance then\n" \
"            local func = self.asFunction(classInstance.tearDown) or self.asFunction(classInstance.TearDown) or\n" \
"                             self.asFunction(classInstance.teardown) or self.asFunction(classInstance.Teardown)\n" \
"            if func then\n" \
"                self:updateStatus(self:protectedCall(classInstance, func, className .. '.tearDown'))\n" \
"            end\n" \
"        end\n" \
"    end\n" \
"\n" \
"    self:endTest()\n" \
"end\n" \
"\n" \
"function M.LuaUnit.expandOneClass(result, className, classInstance)\n" \
"    --[[\n" \
"        Input: a list of { name, instance }, a class name, a class instance\n" \
"        Ouptut: modify result to add all test method instance in the form:\n" \
"        { className.methodName, classInstance }\n" \
"        ]]\n" \
"    for methodName, methodInstance in sortedPairs(classInstance) do\n" \
"        if M.LuaUnit.asFunction(methodInstance) and M.LuaUnit.isMethodTestName(methodName) then\n" \
"            table.insert(result, {className .. '.' .. methodName, classInstance})\n" \
"        end\n" \
"    end\n" \
"end\n" \
"\n" \
"function M.LuaUnit.expandClasses(listOfNameAndInst)\n" \
"    --[[\n" \
"        -- expand all classes (provided as {className, classInstance}) to a list of {className.methodName, classInstance}\n" \
"        -- functions and methods remain untouched\n" \
"\n" \
"        Input: a list of { name, instance }\n" \
"\n" \
"        Output:\n" \
"        * { function name, function instance } : do nothing\n" \
"        * { class.method name, class instance }: do nothing\n" \
"        * { class name, class instance } : add all method names in the form of (className.methodName, classInstance)\n" \
"        ]]\n" \
"    local result = {}\n" \
"\n" \
"    for i, v in ipairs(listOfNameAndInst) do\n" \
"        local name, instance = v[1], v[2]\n" \
"        if M.LuaUnit.asFunction(instance) then\n" \
"            table.insert(result, {name, instance})\n" \
"        else\n" \
"            if type(instance) ~= 'table' then\n" \
"                error('Instance must be a table or a function, not a ' .. type(instance) .. ' with value ' ..\n" \
"                          prettystr(instance))\n" \
"            end\n" \
"            local className, methodName = M.LuaUnit.splitClassMethod(name)\n" \
"            if className then\n" \
"                local methodInstance = instance[methodName]\n" \
"                if methodInstance == nil then\n" \
"                    error(\"Could not find method in class \" .. tostring(className) .. \" for method \" ..\n" \
"                              tostring(methodName))\n" \
"                end\n" \
"                table.insert(result, {name, instance})\n" \
"            else\n" \
"                M.LuaUnit.expandOneClass(result, name, instance)\n" \
"            end\n" \
"        end\n" \
"    end\n" \
"\n" \
"    return result\n" \
"end\n" \
"\n" \
"function M.LuaUnit.applyPatternFilter(patternIncFilter, listOfNameAndInst)\n" \
"    local included, excluded = {}, {}\n" \
"    for i, v in ipairs(listOfNameAndInst) do\n" \
"        -- local name, instance = v[1], v[2]\n" \
"        if patternFilter(patternIncFilter, v[1]) then\n" \
"            table.insert(included, v)\n" \
"        else\n" \
"            table.insert(excluded, v)\n" \
"        end\n" \
"    end\n" \
"    return included, excluded\n" \
"end\n" \
"\n" \
"local function getKeyInListWithGlobalFallback(key, listOfNameAndInst)\n" \
"    local result = nil\n" \
"    for i, v in ipairs(listOfNameAndInst) do\n" \
"        if (listOfNameAndInst[i][1] == key) then\n" \
"            result = listOfNameAndInst[i][2]\n" \
"            break\n" \
"        end\n" \
"    end\n" \
"    if (not M.LuaUnit.asFunction(result)) then\n" \
"        result = _G[key]\n" \
"    end\n" \
"    return result\n" \
"end\n" \
"\n" \
"function M.LuaUnit:setupSuite(listOfNameAndInst)\n" \
"    local setupSuite = getKeyInListWithGlobalFallback(\"setupSuite\", listOfNameAndInst)\n" \
"    if self.asFunction(setupSuite) then\n" \
"        self:updateStatus(self:protectedCall(nil, setupSuite, 'setupSuite'))\n" \
"    end\n" \
"end\n" \
"\n" \
"function M.LuaUnit:teardownSuite(listOfNameAndInst)\n" \
"    local teardownSuite = getKeyInListWithGlobalFallback(\"teardownSuite\", listOfNameAndInst)\n" \
"    if self.asFunction(teardownSuite) then\n" \
"        self:updateStatus(self:protectedCall(nil, teardownSuite, 'teardownSuite'))\n" \
"    end\n" \
"end\n" \
"\n" \
"function M.LuaUnit:setupClass(className, instance)\n" \
"    if type(instance) == 'table' and self.asFunction(instance.setupClass) then\n" \
"        self:updateStatus(self:protectedCall(instance, instance.setupClass, className .. '.setupClass'))\n" \
"    end\n" \
"end\n" \
"\n" \
"function M.LuaUnit:teardownClass(className, instance)\n" \
"    if type(instance) == 'table' and self.asFunction(instance.teardownClass) then\n" \
"        self:updateStatus(self:protectedCall(instance, instance.teardownClass, className .. '.teardownClass'))\n" \
"    end\n" \
"end\n" \
"\n" \
"function M.LuaUnit:internalRunSuiteByInstances(listOfNameAndInst)\n" \
"    --[[ Run an explicit list of tests. Each item of the list must be one of:\n" \
"        * { function name, function instance }\n" \
"        * { class name, class instance }\n" \
"        * { class.method name, class instance }\n" \
"\n" \
"        This function is internal to LuaUnit. The official API to perform this action is runSuiteByInstances()\n" \
"        ]]\n" \
"\n" \
"    local expandedList = self.expandClasses(listOfNameAndInst)\n" \
"    if self.shuffle then\n" \
"        randomizeTable(expandedList)\n" \
"    end\n" \
"    local filteredList, filteredOutList = self.applyPatternFilter(self.patternIncludeFilter, expandedList)\n" \
"\n" \
"    self:startSuite(#filteredList, #filteredOutList)\n" \
"    self:setupSuite(listOfNameAndInst)\n" \
"\n" \
"    for i, v in ipairs(filteredList) do\n" \
"        local name, instance = v[1], v[2]\n" \
"        if M.LuaUnit.asFunction(instance) then\n" \
"            self:execOneFunction(nil, name, nil, instance)\n" \
"        else\n" \
"            -- expandClasses() should have already taken care of sanitizing the input\n" \
"            assert(type(instance) == 'table')\n" \
"            local className, methodName = M.LuaUnit.splitClassMethod(name)\n" \
"            assert(className ~= nil)\n" \
"            local methodInstance = instance[methodName]\n" \
"            assert(methodInstance ~= nil)\n" \
"            self:execOneFunction(className, methodName, instance, methodInstance)\n" \
"        end\n" \
"        if self.result.aborted then\n" \
"            break -- \"--error\" or \"--failure\" option triggered\n" \
"        end\n" \
"    end\n" \
"\n" \
"    if self.lastClassName ~= nil then\n" \
"        self:endClass()\n" \
"    end\n" \
"\n" \
"    self:teardownSuite(listOfNameAndInst)\n" \
"    self:endSuite()\n" \
"\n" \
"    if self.result.aborted then\n" \
"        print(\"LuaUnit ABORTED (as requested by --error or --failure option)\")\n" \
"        self:unregisterSuite()\n" \
"        os.exit(-2, false, 0xDEAD)\n" \
"    end\n" \
"end\n" \
"\n" \
"function M.LuaUnit:internalRunSuiteByNames(listOfName)\n" \
"    --[[ Run LuaUnit with a list of generic names, coming either from command-line or from global\n" \
"            namespace analysis. Convert the list into a list of (name, valid instances (table or function))\n" \
"            and calls internalRunSuiteByInstances.\n" \
"        ]]\n" \
"\n" \
"    local instanceName, instance\n" \
"    local listOfNameAndInst = {}\n" \
"\n" \
"    for i, name in ipairs(listOfName) do\n" \
"        local className, methodName = M.LuaUnit.splitClassMethod(name)\n" \
"        if className then\n" \
"            instanceName = className\n" \
"            instance = _G[instanceName]\n" \
"\n" \
"            if instance == nil then\n" \
"                self:unregisterSuite()\n" \
"                error(\"No such name in global space: \" .. instanceName)\n" \
"            end\n" \
"\n" \
"            if type(instance) ~= 'table' then\n" \
"                self:unregisterSuite()\n" \
"                error('Instance of ' .. instanceName .. ' must be a table, not ' .. type(instance))\n" \
"            end\n" \
"\n" \
"            local methodInstance = instance[methodName]\n" \
"            if methodInstance == nil then\n" \
"                self:unregisterSuite()\n" \
"                error(\"Could not find method in class \" .. tostring(className) .. \" for method \" .. tostring(methodName))\n" \
"            end\n" \
"\n" \
"        else\n" \
"            -- for functions and classes\n" \
"            instanceName = name\n" \
"            instance = _G[instanceName]\n" \
"        end\n" \
"\n" \
"        if instance == nil then\n" \
"            self:unregisterSuite()\n" \
"            error(\"No such name in global space: \" .. instanceName)\n" \
"        end\n" \
"\n" \
"        if (type(instance) ~= 'table' and type(instance) ~= 'function') then\n" \
"            self:unregisterSuite()\n" \
"            error('Name must match a function or a table: ' .. instanceName)\n" \
"        end\n" \
"\n" \
"        table.insert(listOfNameAndInst, {name, instance})\n" \
"    end\n" \
"\n" \
"    self:internalRunSuiteByInstances(listOfNameAndInst)\n" \
"end\n" \
"\n" \
"function M.LuaUnit.run(...)\n" \
"    -- Run some specific test classes.\n" \
"    -- If no arguments are passed, run the class names specified on the\n" \
"    -- command line. If no class name is specified on the command line\n" \
"    -- run all classes whose name starts with 'Test'\n" \
"    --\n" \
"    -- If arguments are passed, they must be strings of the class names\n" \
"    -- that you want to run or generic command line arguments (-o, -p, -v, ...)\n" \
"    local runner = M.LuaUnit.new()\n" \
"    return runner:runSuite(...)\n" \
"end\n" \
"\n" \
"function M.LuaUnit:registerSuite()\n" \
"    -- register the current instance into our global array of instances\n" \
"    -- print('-> Register suite')\n" \
"    M.LuaUnit.instances[#M.LuaUnit.instances + 1] = self\n" \
"end\n" \
"\n" \
"function M.unregisterCurrentSuite()\n" \
"    -- force unregister the last registered suite\n" \
"    table.remove(M.LuaUnit.instances, #M.LuaUnit.instances)\n" \
"end\n" \
"\n" \
"function M.LuaUnit:unregisterSuite()\n" \
"    -- print('<- Unregister suite')\n" \
"    -- remove our current instqances from the global array of instances\n" \
"    local instanceIdx = nil\n" \
"    for i, instance in ipairs(M.LuaUnit.instances) do\n" \
"        if instance == self then\n" \
"            instanceIdx = i\n" \
"            break\n" \
"        end\n" \
"    end\n" \
"\n" \
"    if instanceIdx ~= nil then\n" \
"        table.remove(M.LuaUnit.instances, instanceIdx)\n" \
"        -- print('Unregister done')\n" \
"    end\n" \
"\n" \
"end\n" \
"\n" \
"function M.LuaUnit:initFromArguments(...)\n" \
"    --[[Parses all arguments from either command-line or direct call and set internal\n" \
"        flags of LuaUnit runner according to it.\n" \
"\n" \
"        Return the list of names which were possibly passed on the command-line or as arguments\n" \
"        ]]\n" \
"    local args = {...}\n" \
"    if type(args[1]) == 'table' and args[1].__class__ == 'LuaUnit' then\n" \
"        -- run was called with the syntax M.LuaUnit:runSuite()\n" \
"        -- we support both M.LuaUnit.run() and M.LuaUnit:run()\n" \
"        -- strip out the first argument self to make it a command-line argument list\n" \
"        table.remove(args, 1)\n" \
"    end\n" \
"\n" \
"    if #args == 0 then\n" \
"        args = cmdline_argv\n" \
"    end\n" \
"\n" \
"    local options = pcall_or_abort(M.LuaUnit.parseCmdLine, args)\n" \
"\n" \
"    -- We expect these option fields to be either `nil` or contain\n" \
"    -- valid values, so it's safe to always copy them directly.\n" \
"    self.verbosity = options.verbosity\n" \
"    self.quitOnError = options.quitOnError\n" \
"    self.quitOnFailure = options.quitOnFailure\n" \
"\n" \
"    self.exeRepeat = options.exeRepeat\n" \
"    self.patternIncludeFilter = options.pattern\n" \
"    self.shuffle = options.shuffle\n" \
"\n" \
"    options.output = options.output or os.getenv('LUAUNIT_OUTPUT')\n" \
"    options.fname = options.fname or os.getenv('LUAUNIT_JUNIT_FNAME')\n" \
"\n" \
"    if options.output then\n" \
"        if options.output:lower() == 'junit' and options.fname == nil then\n" \
"            print('With junit output, a filename must be supplied with -n or --name')\n" \
"            os.exit(-1, false, 0xDEAD)\n" \
"        end\n" \
"        pcall_or_abort(self.setOutputType, self, options.output, options.fname)\n" \
"    end\n" \
"\n" \
"    return options.testNames\n" \
"end\n" \
"\n" \
"function M.LuaUnit:runSuite(...)\n" \
"    testNames = self:initFromArguments(...)\n" \
"    self:registerSuite()\n" \
"    self:internalRunSuiteByNames(testNames or M.LuaUnit.collectTests())\n" \
"    self:unregisterSuite()\n" \
"    return self.result.notSuccessCount\n" \
"end\n" \
"\n" \
"function M.LuaUnit:runSuiteByInstances(listOfNameAndInst)\n" \
"    --[[\n" \
"        Run all test functions or tables provided as input.\n" \
"\n" \
"        Input: a list of { name, instance }\n" \
"            instance can either be a function or a table containing test functions starting with the prefix \"test\"\n" \
"\n" \
"        return the number of failures and errors, 0 meaning success\n" \
"        ]]\n" \
"    -- parse the command-line arguments\n" \
"    testNames = self:initFromArguments()\n" \
"    self:registerSuite()\n" \
"    self:internalRunSuiteByInstances(listOfNameAndInst)\n" \
"    self:unregisterSuite()\n" \
"    return self.result.notSuccessCount\n" \
"end\n" \
"\n" \
"-- class LuaUnit\n" \
"\n" \
"-- For compatbility with LuaUnit v2\n" \
"M.run = M.LuaUnit.run\n" \
"M.Run = M.LuaUnit.run\n" \
"\n" \
"function M:setVerbosity(verbosity)\n" \
"    -- set the verbosity value (as integer)\n" \
"    M.LuaUnit.verbosity = verbosity\n" \
"end\n" \
"M.set_verbosity = M.setVerbosity\n" \
"M.SetVerbosity = M.setVerbosity\n" \
"\n" \
"return M\n";
static const char lualib_magic_code[] = "local lapp = require \"pl.lapp\"\n" \
"local shlex = require \"shlex\"\n" \
"\n" \
"local magic = {}\n" \
"\n" \
"setmetatable(magic, magic)\n" \
"\n" \
"---@alias magic.CommandRunner fun(argt: table<string, any>, command: magic.Command, argv: string[], argstr: string)\n" \
"---@alias magic.CellCommandRunner fun(argt: table<string, any>, cell: string)\n" \
"---@class magic.Command\n" \
"---@field public description string\n" \
"---@field public runner magic.CommandRunner\n" \
"---@field public raw boolean\n" \
"\n" \
"---@type table<string, magic.Command>\n" \
"local commands = {}\n" \
"\n" \
"---@class magic.CellCommand\n" \
"---@field public description string\n" \
"---@field public runner magic.CellCommandRunner\n" \
"\n" \
"---@type table<string, magic.CellCommand>\n" \
"local cell_commands = {}\n" \
"\n" \
"---register a magic command\n" \
"---@param prefix string\n" \
"---@param description string\n" \
"---@param runner magic.CommandRunner\n" \
"---@param raw? boolean\n" \
"function magic.register(prefix, description, runner, raw)\n" \
"    raw = choose(raw ~= nil, raw, false)\n" \
"    commands[prefix] = {description = description, runner = runner, raw = raw}\n" \
"end\n" \
"\n" \
"---register a magic cell command\n" \
"---@param prefix string\n" \
"---@param description string\n" \
"---@param runner magic.CellCommandRunner\n" \
"function magic.register_cell(prefix, description, runner)\n" \
"    cell_commands[prefix] = {description = description, runner = runner}\n" \
"end\n" \
"\n" \
"---@param command string\n" \
"function magic.run(command)\n" \
"    ---@type string[]\n" \
"    local argv = shlex.split(command)\n" \
"    assert(#argv >= 1, \"No magic command: \" .. command)\n" \
"    local prefix = argv[1]\n" \
"\n" \
"    local command_handler = commands[prefix]\n" \
"\n" \
"    assert(command_handler ~= nil, \"No magic command: \" .. prefix)\n" \
"\n" \
"    -- on raw command skip string processing\n" \
"    if command_handler.raw then\n" \
"        command_handler.runner({}, command_handler, list.slice(argv, 2), command)\n" \
"        return\n" \
"    end\n" \
"\n" \
"    local argt = lapp.process_options_string(command_handler.description, list.slice(argv, 2))\n" \
"    -- help returns nil\n" \
"    if argt ~= nil then\n" \
"        command_handler.runner(argt, command_handler, list.slice(argv, 2), command)\n" \
"    end\n" \
"end\n" \
"\n" \
"---@param command string\n" \
"function magic:__call(command)\n" \
"    magic.run(command)\n" \
"end\n" \
"\n" \
"function magic.run_cell(command, cell)\n" \
"    ---@type string[]\n" \
"    local argv = stringx.split(command)\n" \
"    assert(#argv >= 1, \"No magic command: \" .. command)\n" \
"    local prefix = argv[1]\n" \
"\n" \
"    local command_handler = cell_commands[prefix]\n" \
"\n" \
"    assert(command_handler ~= nil, \"No magic command: \" .. prefix)\n" \
"\n" \
"    local argt = lapp.process_options_string(command_handler.description, list.slice(argv, 2))\n" \
"    -- help returns nil\n" \
"    if argt ~= nil then\n" \
"        command_handler.runner(argt, cell)\n" \
"    end\n" \
"end\n" \
"\n" \
"---@return string[]\n" \
"function magic.commands()\n" \
"    return tablex.keys(commands)\n" \
"end\n" \
"\n" \
"---@return string[]\n" \
"function magic.cell_commands()\n" \
"    return tablex.keys(cell_commands)\n" \
"end\n" \
"\n" \
"return magic\n";
