"\n" \
"return re\n";
static const char lualib_regmap_code[] = "---@module 'regmap'\n" \
"local regmap = {}\n" \
"\n" \
"local cjson = require \"cjson\"\n" \
"\n" \
"local pf = require \"pl.file\"\n" \
"local class = require \"pl.class\"\n" \
"local intmod = require \"int\"\n" \
"\n" \
"---@class RegisterSegment\n" \
"---@field public address_offset integer\n" \
"---@field public width integer\n" \
"---@field public lsb integer\n" \
"---@field public reg_lsb integer\n" \
"\n" \
"---@class RegisterField:pl.Class\n" \
"---@field public name string\n" \
"---@field public segments RegisterSegment[]\n" \
"local RegisterField = class()\n" \
"\n" \
"regmap.RegisterField = RegisterField\n" \
"\n" \
"local function bin_to_signed(val, width)\n" \
"    return val - ((val << 1) & (1 << width))\n" \
"end\n" \
"\n" \
"function RegisterField:_init(name, field)\n" \
"    ---@type string\n" \
"    self.name = name\n" \
"    ---@type integer[]\n" \
"    self.base_addresses = field[\"bases\"]\n" \
"    ---@type boolean\n" \
"    self.read_only = field[\"RO\"]\n" \
"    ---@type boolean\n" \
"    self.signed = field[\"sign\"]\n" \
"    ---@type integer\n" \
"    self.width = 0\n" \
"    ---@type RegisterSegment[]\n" \
"    self.segments = {}\n" \
"    for segment in iter(range(field.parts)) do\n" \
"        self.segments[segment] = {\n" \
"            address_offset = field[\"addr\"][segment],\n" \
"            width = field[\"width\"][segment],\n" \
"            lsb = field[\"lsb\"][segment],\n" \
"            reg_lsb = field[\"reg_lsb\"][segment]\n" \
"        }\n" \
"        self.width = self.width + field[\"width\"][segment]\n" \
"    end\n" \
"end\n" \
"\n" \
"function RegisterField:__tostring()\n" \
"    return inspect({\n" \
"        name = self.name,\n" \
"        base_addresses = list.map(self.base_addresses, hex),\n" \
"        read_only = self.read_only,\n" \
"        segments = self.segments\n" \
"    }, {rawstring = true})\n" \
"\n" \
"end\n" \
"\n" \
"---Read multiple indices at once\n" \
"---@param slice integer\n" \
"---@param indices? integer[] indices to read default is all\n" \
"---@return integer[]\n" \
"function RegisterField:read_all(slice, indices)\n" \
"    if indices == nil then\n" \
"        indices = range(0, #self.base_addresses - 1)\n" \
"    end\n" \
"    return list.map(indices, function(index)\n" \
"        return self:read(slice, index)\n" \
"    end)\n" \
"end\n" \
"\n" \
"---Write multiple indices at once\n" \
"---@param slice integer\n" \
"---@param value integer\n" \
"---@param indices? integer[]\n" \
"function RegisterField:write_all(slice, value, indices)\n" \
"    if indices == nil then\n" \
"        indices = range(0, #self.base_addresses - 1)\n" \
"    end\n" \
"    return list.foreach(indices, function(index)\n" \
"        self:write(slice, value, index)\n" \
"    end)\n" \
"end\n" \
"\n" \
"--- Read specific bits of field\n" \
"---@note These are Field Bits not Segment Bits\n" \
"---@param slice integer\n" \
"---@param index integer\n" \
"---@param msb? integer\n" \
"---@param lsb? integer\n" \
"---@return integer\n" \
"function RegisterField:read_bits(slice, index, msb, lsb)\n" \
"    local value = self:read(slice, index)\n" \
"    lsb = lsb or msb or 0\n" \
"    msb = msb or self.width\n" \
"    if lsb > msb then\n" \
"        msb, lsb = lsb, msb\n" \
"    end\n" \
"    return intmod.bitget(value, msb, lsb)\n" \
"end\n" \
"\n" \
"--- Write specific bits of the field\n" \
"---@note These are Field Bits not Segment Bits\n" \
"---@param slice integer\n" \
"---@param index integer\n" \
"---@param value integer\n" \
"---@param msb? integer\n" \
"---@param lsb? integer\n" \
"---@return integer\n" \
"function RegisterField:write_bits(slice, value, index, msb, lsb)\n" \
"    lsb = lsb or msb or 0\n" \
"    msb = msb or self.width\n" \
"    if lsb > msb then\n" \
"        msb, lsb = lsb, msb\n" \
"    end\n" \
"\n" \
"    if msb == self.width and lsb == 0 then\n" \
"        self:write(slice, value, index)\n" \
"    else\n" \
"        local old_val = self:read(slice, index)\n" \
"        self:write(slice, intmod.bitset(old_val, value, msb, lsb), index)\n" \
"    end\n" \
"\n" \
"    return (value >> lsb) & (((1 << (msb + 1)) - 1) >> lsb)\n" \
"end\n" \
"\n" \
"---@param slice integer\n" \
"---@param index? integer\n" \
"---@return integer\n" \
"function RegisterField:read(slice, index)\n" \
"    if index == nil then\n" \
"        index = 0\n" \
"    end\n" \
"    local val = 0\n" \
"    local base_address = self.base_addresses[index + 1]\n" \
"    assert(base_address ~= nil, \"Invalid Index %s\" % {index})\n" \
"    for segment in iter(self.segments) do\n" \
"        local segval = credo.slice_read(slice, int(base_address + segment.address_offset),\n" \
"                                        segment.lsb + segment.width - 1, segment.lsb)\n" \
"        val = val | (segval << segment.reg_lsb)\n" \
"    end\n" \
"    if self.signed then\n" \
"        val = bin_to_signed(val, self.width)\n" \
"    end\n" \
"    return val\n" \
"end\n" \
"\n" \
"---@param slice integer\n" \
"---@param value integer\n" \
"---@param index? integer\n" \
"function RegisterField:write(slice, value, index)\n" \
"    if index == nil then\n" \
"        index = 0\n" \
"    end\n" \
"    assert(not self.read_only, \"%s is read only\" % {self.name})\n" \
"    local base_address = self.base_addresses[index + 1]\n" \
"    assert(base_address ~= nil, \"Invalid Index %s\" % {index})\n" \
"\n" \
"    for segment in iter(self.segments) do\n" \
"        local segval = (value >> segment.reg_lsb)\n" \
"        credo.slice_write(slice, int(base_address + segment.address_offset), segval, segment.lsb + segment.width - 1,\n" \
"                          segment.lsb)\n" \
"    end\n" \
"end\n" \
"\n" \
"---@alias RegisterHive table<string, RegisterField>\n" \
"\n" \
"---@class RegisterHiveClass: pl.Class\n" \
"local RegisterHive = class()\n" \
"\n" \
"---@param name string\n" \
"---@param fields any\n" \
"function RegisterHive:_init(name, fields)\n" \
"    self.name = name\n" \
"    for fieldname, field in pairs(fields) do\n" \
"        fieldname = string.lower(fieldname)\n" \
"        self[fieldname] = RegisterField(fieldname, field)\n" \
"    end\n" \
"end\n" \
"\n" \
"---@alias RegisterMap table<string, RegisterHive>\n" \
"\n" \
"---@class RegisterMapClass: pl.Class\n" \
"local RegisterMap = class()\n" \
"\n" \
"function RegisterMap:_init(filename, regmap_data)\n" \
"    self.filename = filename\n" \
"    for hive_name, hive in pairs(regmap_data) do\n" \
"        hive_name = string.lower(hive_name)\n" \
"        if type(hive) ~= \"table\" then\n" \
"            goto continue\n" \
"        end\n" \
"        self[hive_name] = RegisterHive(hive_name, hive[\"regs\"])\n" \
"        ::continue::\n" \
"    end\n" \
"end\n" \
"\n" \
"---@param file string\n" \
"---@param is_module? boolean default false\n" \
"---@return RegisterMap\n" \
"function regmap.load(file, is_module)\n" \
"    local data\n" \
"    if is_module == true then\n" \
"        local text = require(file).data()\n" \
"        data = cjson.decode(text)\n" \
"    else\n" \
"        data = cjson.decode(pf.read(file))\n" \
"    end\n" \
"    return RegisterMap(file, data)\n" \
"end\n" \
"\n" \
"---@type table<string, RegisterMap>\n" \
"local regmap_cache = {}\n" \
"\n" \
"local function get_regmap_module(slice)\n" \
"    local dev_type = credo.slice_get_device_type(slice)\n" \
"    if list.contains({credo.DEV_BLACKHAWK_800, credo.DEV_BLACKHAWK_400}, dev_type) then\n" \
"        return \"regmap.blackhawk\"\n" \
"    elseif list.contains({credo.DEV_OWL_400, credo.DEV_OWL_800}, dev_type) then\n" \
"        return \"regmap.owl\"\n" \
"    elseif list.contains({credo.DEV_OSPREY_400, credo.DEV_OSPREY_800}, dev_type) then\n" \
"        return \"regmap.osprey\"\n" \
"    elseif list.contains({credo.DEV_HERON_1P0, credo.DEV_HERON_MR}, dev_type) then\n" \
"        return \"regmap.heron1p0\"\n" \
"    elseif list.contains({credo.DEV_NUTCRACKER_32}, dev_type) then\n" \
"        return \"regmap.nutcracker\"\n" \
"    elseif list.contains({credo.DEV_SCREAMING_EAGLE, credo.DEV_SCREAMING_EAGLE_AEC}, dev_type) then\n" \
"        return \"regmap.screaming_eagle\"\n" \
"    elseif list.contains({credo.DEV_NIGHTHAWK}, dev_type) then\n" \
"        return \"regmap.nighthawk\"\n" \
"    elseif list.contains({credo.DEV_NIGHTHAWK_1P0}, dev_type) then\n" \
"        return \"regmap.nighthawk1p0\"\n" \
"    elseif list.contains({credo.DEV_MONARCH2P1_TEST, credo.DEV_MONARCH2P1}, dev_type) then\n" \
"        return \"regmap.monarch2p1\"\n" \
"    elseif list.contains({credo.DEV_SKIPPER_TEST, credo.DEV_SKIPPER}, dev_type) then\n" \
"        return \"regmap.skipper\"\n" \
"    else\n" \
"        return nil\n" \
"    end\n" \
"end\n" \
"\n" \
"---Get register map for slice\n" \
"---Uses a cache to make sure that a given register map is only loaded once\n" \
"---@param slice integer\n" \
"---@return RegisterMap\n" \
"function regmap.slice(slice)\n" \
"    local module = get_regmap_module(slice)\n" \
"    if module == nil then\n" \
"        error(\"No register map for slice %d\" % {slice})\n" \
"    end\n" \
"    local cache_map = regmap_cache[module]\n" \
"    if cache_map ~= nil then\n" \
"        return cache_map\n" \
"    end\n" \
"    regmap_cache[module] = regmap.load(module, true)\n" \
"    return regmap_cache[module]\n" \
"end\n" \
"\n" \
"return regmap\n";
