static const char lualib_regmap_generate_code[] = "local zlib = require \"zlib\"\n" \
"local b64 = require \"base64\"\n" \
"local pf = require \"pl.file\"\n" \
"\n" \
"local gen = {}\n" \
"\n" \
"-- make sure that ci/customer_regmap.py is used first before generating the register maps\n" \
"\n" \
"---@param path string\n" \
"---@param chip string\n" \
"function gen.generate(path, chip)\n" \
"\n" \
"    local regmap = pf.read(path)\n" \
"\n" \
"    ---@cast regmap string|nil\n" \
"    assert(regmap ~= nil, \"Regmap not found\")\n" \
"\n" \
"    local regmap_comp = zlib.compress(regmap)\n" \
"    local regmap_comp_ascii = b64.encode(regmap_comp)\n" \
"    regmap_comp_ascii = string.gsub(regmap_comp_ascii, \"\\n\", [[\\z]] .. \"\\n\")\n" \
"    regmap_comp_ascii = regmap_comp_ascii:sub(1, -4)\n" \
"\n" \
"    local module = [==[\n" \
"local zlib = require \"zlib\"\n" \
"local b64 = require \"base64\"\n" \
"local data = \"\\z\n" \
"%s\"\n" \
"\n" \
"local decompressed = zlib.decompress(b64.decode(data))\n" \
"local regmap = {}\n" \
"---@return string\n" \
"function regmap.data()\n" \
"    return decompressed\n" \
"end\n" \
"return regmap\n" \
"]==] % {regmap_comp_ascii}\n" \
"\n" \
"    pf.write(\"%s.lua\" % {chip}, module)\n" \
"end\n" \
"\n" \
"return gen\n";
