"function shell.select_slices(slices)\n" \
"\n" \
"    local slice_id_map = shell.get_slice_list()\n" \
"    -- skip non-existant slices\n" \
"    slices = list.filter(slices, function(value)\n" \
"        return list.contains(slice_id_map, value)\n" \
"    end)\n" \
"    if #slices == 0 then\n" \
"        error(\"must give nonzero number of slices\")\n" \
"    end\n" \
"\n" \
"    local shared_family = credo.slice_get_family(slices[1])\n" \
"    for slice in iter(slices) do\n" \
"        local family = credo.slice_get_family(slice)\n" \
"        assert(shared_family == family, \"All slices must be of the same family\")\n" \
"    end\n" \
"\n" \
"    local slice_selected_map = list.map(slice_id_map, function(slice_id)\n" \
"        return list.contains(slices, slice_id)\n" \
"    end)\n" \
"    _shell.set_selected_slices(slice_selected_map)\n" \
"end\n" \
"\n" \
"--- get selected slices\n" \
"---@return integer[]\n" \
"function shell.get_selected_slices()\n" \
"    return _shell.get_selected_slices()\n" \
"end\n" \
"\n" \
"---return the first slice of the selected slices\n" \
"---useful for functions when the slice type is needed for the selected slices\n" \
"---@return integer\n" \
"function shell.get_selected_slice()\n" \
"    return shell.get_selected_slices()[1]\n" \
"end\n" \
"\n" \
"function shell.print_device_tree()\n" \
"    local dev_index = 0\n" \
"    local ftable = fort.create()\n" \
"    local selected_slices = shell.get_selected_slices()\n" \
"    local dev_tree = om()\n" \
"    for slice in iter(shell.get_slice_list()) do\n" \
"        local device = credo.slice_get_device(slice)\n" \
"        if dev_tree[device] == nil then\n" \
"            dev_tree[device] = {}\n" \
"        end\n" \
"        table.insert(dev_tree[device], slice)\n" \
"    end\n" \
"    for dev, slices in pairs(dev_tree) do\n" \
"        dev_index = dev_index + 1\n" \
"        local first_slice = slices[1]\n" \
"        local device_type = credo.slice_get_device_type(first_slice)\n" \
"        for slice in iter(slices) do\n" \
"            if slice == first_slice then\n" \
"                ftable:print(\"%s|%s\" % {string.lower(device_type.display_name), string.char((dev_index % 26) + 96)})\n" \
"            else\n" \
"                ftable:print(\"|\")\n" \
"            end\n" \
"            ftable:print_ln(\"Slice %d%s\" % {slice, choose(list.contains(selected_slices, slice), \" [*]\", \"\")})\n" \
"        end\n" \
"    end\n" \
"    ftable:set_border_style(fort.EMPTY_STYLE)\n" \
"    print(ftable)\n" \
"end\n" \
"\n" \
"---@param lc lightuserdata\n" \
"---@param str string\n" \
"---@param pos integer\n" \
"function shell.add_completion(lc, str, pos)\n" \
"    _shell.add_completion(lc, str, pos)\n" \
"end\n" \
"\n" \
"---Get user input\n" \
"---@param prompt string|nil\n" \
"---@return string\n" \
"function shell.input(prompt)\n" \
"    return _shell.input(prompt)\n" \
"end\n" \
"\n" \
"---@param str string\n" \
"function shell.write(str)\n" \
"    _shell.write(str)\n" \
"end\n" \
"\n" \
"---@param str string\n" \
"function shell.write_error(str)\n" \
"    _shell.write_error(str)\n" \
"end\n" \
"\n" \
"return shell\n";
static const char lualib_shlex_code[] = "---@module 'shlex'\n" \
"-- similar to python shlex library\n" \
"local shlex = {}\n" \
"\n" \
"--- custom argsplit that handles quotes + escaped quotes\n" \
"--- naive support for escaping and quoting, but not a true posix splitter as it would require a PEG parser\n" \
"---@param text string\n" \
"---@return string[]\n" \
"function shlex.split(text)\n" \
"    local spat, epat, buf, quoted = [=[^(['\"])]=], [=[(['\"])$]=], nil, nil\n" \
"    local args = {}\n" \
"    for str in text:gmatch(\"%S+\") do\n" \
"        local squoted = str:match(spat)\n" \
"        local equoted = str:match(epat)\n" \
"        local escaped = str:match([=[(\\*)['\"]$]=])\n" \
"        if squoted and not quoted and not equoted then\n" \
"            buf, quoted = str, squoted\n" \
"        elseif buf and equoted == quoted and #escaped % 2 == 0 then\n" \
"            str, buf, quoted = buf .. ' ' .. str, nil, nil\n" \
"        elseif buf then\n" \
"            buf = buf .. ' ' .. str\n" \
"        end\n" \
"        if not buf then\n" \
"            list.append(args, (str:gsub(spat, \"\"):gsub(epat, \"\")))\n" \
"        end\n" \
"    end\n" \
"    if buf then\n" \
"        error(\"Missing matching quote for \" .. buf, 2)\n" \
"    end\n" \
"    return args\n" \
"end\n" \
"\n" \
"return shlex\n";
static const char lualib_slash_code[] = "local utils = require \"pl.utils\"\n" \
"local class = require \"pl.class\"\n" \
"local lapp = require \"pl.lapp\"\n" \
"local shlex = require \"shlex\"\n" \
"\n" \
"local credo = require \"credo\"\n" \
"local shell = require \"shell\"\n" \
"\n" \
"local slash = {}\n" \
"\n" \
"lapp.show_usage_error = \"throw\"\n" \
"lapp.slack = true\n" \
"\n" \
"---@alias slash.CommandRunner fun(slice: integer, argt: table<string, any>, argv: string[])\n" \
"---@alias slash.CommandRunnerMulti fun(slices: integer[], argt: table<string, any>, argv: string[])\n" \
"\n" \
"-- Command Creation\n" \
"---@class slash.Command\n" \
"---@field public path string[]\n" \
"---@field public description string\n" \
"---@field public runner slash.CommandRunner\n" \
"---@field public raw boolean\n" \
"---@overload fun(path: string[], description: string, runner: slash.CommandRunner, raw?: integer): slash.Command\n" \
"local Command = class()\n" \
"\n" \
"slash.Command = Command\n" \
"\n" \
"---Create the command\n" \
"---@param path string[]\n" \
"---@param description string\n" \
"---@param runner slash.CommandRunner\n" \
"---@param flags? integer\n" \
"function Command:_init(path, description, runner, flags)\n" \
"    self.path = path\n" \
"    self.description = description\n" \
"    self.runner = runner\n" \
"    flags = flags or 0\n" \
"    local raw = choose(flags & slash.RAW ~= 0, true, false)\n" \
"    local multislice = choose(flags & slash.MULTISLICE ~= 0, true, false)\n" \
"    self.raw = raw\n" \
"    self.multislice = multislice\n" \
"end\n" \
"\n" \
"---Check that a provided path matches\n" \
"---@param argv string[]\n" \
"---@param subpath? boolean matches as a subpath\n" \
"---@return boolean,integer\n" \
"function Command:matches_path(argv, subpath)\n" \
"    if subpath == nil then\n" \
"        subpath = false\n" \
"    end\n" \
"    if not subpath and #argv < #self.path then\n" \
"        return false, 0\n" \
"    end\n" \
"    for index, path_item in ipairs(self.path) do\n" \
"        if subpath and argv[index] == nil then\n" \
"            break\n" \
"        end\n" \
"        if argv[index] ~= path_item then\n" \
"            return false, 0\n" \
"        end\n" \
"    end\n" \
"    return true, #self.path\n" \
"end\n" \
"\n" \
"---@param path string[]\n" \
"---@param verbose? boolean\n" \
"function slash.print_possible_commands(path, verbose)\n" \
"    local path_name = stringx.join(\" \", path)\n" \
"    local output = \"\"\n" \
"\n" \
"    local slash_commands = slash.get_all_commands()\n" \
"\n" \
"    table.sort(slash_commands, function(a, b)\n" \
"        return stringx.join(\" \", a.path) < stringx.join(\" \", b.path)\n" \
"    end)\n" \
"\n" \
"    local sub_commands = list.filter(slash_commands, function(command)\n" \
"        local command_name = stringx.join(\" \", command.path)\n" \
"        return #path == 0 or stringx.startswith(command_name, path_name)\n" \
"    end)\n" \
"    local sub_commands_count = #sub_commands\n" \
"\n" \
"    if sub_commands_count == 0 then\n" \
"        error(\"Invalid command path: \" .. path_name)\n" \
"    end\n" \
"\n" \
"    ---@param command slash.Command\n" \
"    for command in iter(sub_commands) do\n" \
"        local command_name = stringx.join(\" \", command.path)\n" \
"        if not verbose and sub_commands_count > 1 then\n" \
"            output = output .. command_name .. \"\\n\"\n" \
"        else\n" \
"            output = \"%s%s\\n%s\\n%s\\n\" % {output, command_name, string.gsub(command_name, \".\", \"-\"), command.description}\n" \
"        end\n" \
"    end\n" \
"    print(output)\n" \
"end\n" \
"\n" \
"---@param argv string[]\n" \
"---@return integer\n" \
"local function get_subcommand_count(argv)\n" \
"    local match_count = 0\n" \
"    for _, slash_command in ipairs(slash.get_all_commands()) do\n" \
"        local cmd_matches, cmd_match_count = slash_command:matches_path(argv, true)\n" \
"        if cmd_matches and cmd_match_count > #argv then\n" \
"            match_count = match_count + 1\n" \
"        end\n" \
"    end\n" \
"    return match_count\n" \
"end\n" \
"\n" \
"---Run the shell command\n" \
"---@param argv string[]\n" \
"function Command:run(argv)\n" \
"\n" \
"    local sub_argv = list.slice(argv, #self.path + 1)\n" \
"    if list.contains(sub_argv, \"?\") then\n" \
"        print(self.description)\n" \
"        local match_count = get_subcommand_count(self.path)\n" \
"        if match_count > 1 then\n" \
"            print(\"Sub Commands\\n------------\")\n" \
"            slash.print_possible_commands(self.path)\n" \
"        end\n" \
"        return\n" \
"    end\n" \
"\n" \
"    local slice_list_selected = shell.get_selected_slices()\n" \
"    local function runner(slice)\n" \
"        -- cannot lapp.process on raw command\n" \
"        if self.raw then\n" \
"            return self.runner(slice, {}, argv)\n" \
"        end\n" \
"        local argt = lapp.process_options_string(self.description, sub_argv)\n" \
"        -- help returns nil\n" \
"        if argt ~= nil then\n" \
"            return self.runner(slice, argt, argv)\n" \
"        else\n" \
"            return \"help\"\n" \
"        end\n" \
"    end\n" \
"\n" \
"    if self.multislice then\n" \
"        runner(slice_list_selected)\n" \
"    else\n" \
"        for slice in iter(slice_list_selected) do\n" \
"            if #slice_list_selected > 1 then\n" \
"                print(\"Slice %d\" % {slice})\n" \
"            end\n" \
"            local res = runner(slice)\n" \
"            if res == \"help\" then\n" \
"                break\n" \
"            end\n" \
"        end\n" \
"    end\n" \
"end\n" \
"\n" \
"-- Command Creation\n" \
"---@class slash.Type\n" \
"---@field public name string\n" \
"---@field public description string\n" \
"---@field public parser fun(raw: string):any\n" \
"slash.Type = class()\n" \
"\n" \
"---Create the command\n" \
"---@param name string\n" \
"---@param description string\n" \
"---@param parser fun(raw: string):any\n" \
"function slash.Type:_init(name, description, parser)\n" \
"    self.name = name\n" \
"    self.description = description\n" \
"    self.parser = parser\n" \
"end\n" \
"\n" \
"-- Command Registration\n" \
"\n" \
"---@type slash.Command[]\n" \
"slash.commands = {}\n" \
"\n" \
"---@type table<string, slash.Type>\n" \
"slash.types = {}\n" \
"\n" \
"---@type table<credo.Family, slash.Command[]>\n" \
"slash.chip_commands = {}\n" \
"\n" \
"---@return slash.Command[]\n" \
"function slash.get_all_commands(slice)\n" \
"    slice = slice or shell.get_selected_slice()\n" \
"    local slice_family = credo.slice_get_family(slice)\n" \
"    local chip_commands = slash.chip_commands[slice_family.value]\n" \
"    if chip_commands == nil then\n" \
"        return list.new(slash.commands)\n" \
"    end\n" \
"    local commands = list()\n" \
"    list.extend(commands, chip_commands)\n" \
"    -- Allow chip commands to override/shadow builtin commands\n" \
"    ---@param command slash.Command\n" \
"    for command in iter(slash.commands) do\n" \
"        if #list.filter(commands, function(chip_command)\n" \
"            local match = command:matches_path(chip_command.path)\n" \
"            return match and #chip_command.path == #command.path\n" \
"        end) == 0 then\n" \
"            list.append(commands, command)\n" \
"        end\n" \
"    end\n" \
"\n" \
"    return commands\n" \
"end\n" \
"\n" \
"---Get all types\n" \
"---@return table<string,slash.Type>\n" \
"function slash.get_all_types()\n" \
"    return tablex.copy(slash.types)\n" \
"end\n" \
"\n" \
"slash.RAW = 0x1\n" \
"slash.MULTISLICE = 0x2\n" \
"\n" \
"---register a command\n" \
"---@param path string[]\n" \
"---@param description string\n" \
"---@param runner slash.CommandRunner\n" \
"---@param flags? integer\n" \
"function slash.register_command(path, description, runner, flags)\n" \
"    assert(type(path) == \"table\")\n" \
"    table.insert(slash.commands, 1, slash.Command(path, description, runner, flags))\n" \
"end\n" \
"\n" \
"---register a lapp type\n" \
"---@param name string\n" \
"---@param description string\n" \
"---@param parser fun(raw: string):any\n" \
"function slash.register_type(name, description, parser)\n" \
"    assert(type(name) == \"string\")\n" \
"    slash.types[name] = slash.Type(name, description, parser)\n" \
"    lapp.add_type(name, parser)\n" \
"end\n" \
"\n" \
"---register a chip command\n" \
"---@param path string[]\n" \
"---@param family credo.Family\n" \
"---@param description string\n" \
"---@param runner slash.CommandRunner\n" \
"function slash.register_chip_command(path, family, description, runner, flags)\n" \
"    if slash.chip_commands[family.value] == nil then\n" \
"        slash.chip_commands[family.value] = {}\n" \
"    end\n" \
"    table.insert(slash.chip_commands[family.value], 1, slash.Command(path, description, runner, flags))\n" \
"end\n" \
"\n" \
"---register a multi chip command\n" \
"---@param path string[]\n" \
"---@param family credo.Family\n" \
"---@param description string\n" \
"---@param runner slash.CommandRunnerMulti\n" \
"function slash.register_chip_command_multi(path, family, description, runner)\n" \
"    slash.register_chip_command(path, family, description, runner, slash.MULTISLICE)\n" \
"end\n" \
"\n" \
"---register a chip alias command\n" \
"---@param base_path string[]\n" \
"---@param alias_path string[]\n" \
"---@param family credo.Family\n" \
"function slash.register_chip_command_alias(base_path, alias_path, family)\n" \
"\n" \
"    ---@type slash.Command[]\n" \
"    local chip_commands = slash.chip_commands[family.value]\n" \
"    assert(chip_commands ~= nil, \"Invalid family for alias: %s\" % {family})\n" \
"\n" \
"    for chip_command in iter(chip_commands) do\n" \
"        if list(base_path) == list(chip_command.path) then\n" \
"            list.append(chip_commands, slash.Command(alias_path, chip_command.description, chip_command.runner, choose(\n" \
"                                                         chip_command.multislice, slash.MULTISLICE, 0) |\n" \
"                                                         choose(chip_command.raw, slash.RAW, 0)))\n" \
"            return\n" \
"        end\n" \
"    end\n" \
"    error(\"Unable to find base path %s to alias\", inspect(base_path))\n" \
"end\n" \
"\n" \
"-- Command Parsing / Running\n" \
"\n" \
"---run a basic command\n" \
"---@param command string\n" \
"local function run_command(command)\n" \
"    local base_command = command\n" \
"    ---@type string[] split into command vector (argv like)\n" \
"    local argv = shlex.split(command)\n" \
"    -- empty line or just full of only spaces\n" \
"    if #argv == 0 then\n" \
"        return\n" \
"    end\n" \
"    ---@type slash.Command\n" \
"    local selected_command = nil\n" \
"    local selected_match_count = 0\n" \
"    for _, slash_command in ipairs(slash.get_all_commands()) do\n" \
"        local cmd_matches, cmd_match_count = slash_command:matches_path(argv)\n" \
"        if cmd_matches and cmd_match_count > selected_match_count then\n" \
"            selected_command = slash_command\n" \
"            selected_match_count = cmd_match_count\n" \
"        end\n" \
"    end\n" \
"\n" \
"    if selected_command ~= nil then\n" \
"        selected_command:run(argv)\n" \
"    elseif #argv > 0 and stringx.endswith(argv[#argv], \"?\") then\n" \
"        argv[#argv] = stringx.removesuffix(argv[#argv], \"?\")\n" \
"        if argv[#argv] == \"\" then\n" \
"            argv = list.slice(argv, 1, -1)\n" \
"        end\n" \
"        slash.print_possible_commands(argv, false)\n" \
"    else\n" \
"        error(\"Invalid command %s\" % {base_command})\n" \
"    end\n" \
"end\n" \
"\n" \
"---Run a commandset which can be a 1 or many slash.commands\n" \
"---@param commandset string\n" \
"function slash.run(commandset)\n" \
"    ---@type string[]\n" \
"    local commandset_list = utils.split(commandset, \"[;\\n]\")\n" \
"    for command in list.iterate(commandset_list) do\n" \
"        command = stringx.strip(command) -- remove whitespace\n" \
"        command = stringx.removeprefix(command, \"/\") -- remove '/' prefix\n" \
"        -- ignore any comments in the line\n" \
"        if stringx.count(command, \"#\") > 0 then\n" \
"            command = stringx.partition(command, \"#\")\n" \
"        end\n" \
"        if #command > 0 then\n" \
"            run_command(command)\n" \
"        end\n" \
"    end\n" \
"end\n" \
"\n" \
"setmetatable(slash, slash)\n" \
"\n" \
"---@param commandset string\n" \
"---@param slice? integer|nil\n" \
"function slash:__call(commandset, slice)\n" \
"    if slice ~= nil then\n" \
"        slash.run(\"slice %d\" % {slice})\n" \
"    end\n" \
"    slash.run(commandset)\n" \
"end\n" \
"\n" \
"return slash\n";
