"        end\n" \
"        if options.margin.bottom then\n" \
"            ftable:set_tbl_prop(fort.TPROP_BOTTOM_MARGIN, options.margin.bottom)\n" \
"        end\n" \
"        if options.margin.right then\n" \
"            ftable:set_tbl_prop(fort.TPROP_RIGHT_MARGIN, options.margin.right)\n" \
"        end\n" \
"    end\n" \
"\n" \
"    --- set text alignment\n" \
"    if options.align then\n" \
"        for col_name, text_align in pairs(options.align) do\n" \
"            assert(text_align_mapping[text_align], \"tabulate: invalid text align:\" .. tostring(text_align))\n" \
"            ftable:set_cell_prop(fort.ANY_ROW, column_index_map[col_name], fort.CPROP_TEXT_ALIGN,\n" \
"                                 text_align_mapping[text_align])\n" \
"        end\n" \
"    end\n" \
"\n" \
"    --- set footer alignment\n" \
"    if options.footer_align then\n" \
"        for col_name, text_align in pairs(options.footer_align) do\n" \
"            assert(text_align_mapping[text_align], \"tabulate: invalid footer align:\" .. tostring(text_align))\n" \
"            ftable:set_cell_prop(-1, footer_index_map[col_name], fort.CPROP_TEXT_ALIGN, text_align_mapping[text_align])\n" \
"        end\n" \
"    end\n" \
"\n" \
"    -- set generic padding\n" \
"    local tbl_padding = options.padding or {}\n" \
"    if tbl_padding.top ~= nil then\n" \
"        ftable:set_cell_prop(fort.ANY_ROW, fort.ANY_COLUMN, fort.CPROP_TOP_PADDING, tbl_padding.top)\n" \
"    end\n" \
"    if tbl_padding.left ~= nil then\n" \
"        ftable:set_cell_prop(fort.ANY_ROW, fort.ANY_COLUMN, fort.CPROP_LEFT_PADDING, tbl_padding.left)\n" \
"    end\n" \
"    if tbl_padding.bottom ~= nil then\n" \
"        ftable:set_cell_prop(fort.ANY_ROW, fort.ANY_COLUMN, fort.CPROP_BOTTOM_PADDING, tbl_padding.bottom)\n" \
"    end\n" \
"    if tbl_padding.right ~= nil then\n" \
"        ftable:set_cell_prop(fort.ANY_ROW, fort.ANY_COLUMN, fort.CPROP_RIGHT_PADDING, tbl_padding.right)\n" \
"    end\n" \
"\n" \
"    --- set column padding, after generic padding to override\n" \
"    if options.col_padding then\n" \
"        for col_name, padding in pairs(options.col_padding) do\n" \
"            if padding.top ~= nil then\n" \
"                ftable:set_cell_prop(fort.ANY_ROW, column_index_map[col_name], fort.CPROP_TOP_PADDING, padding.top)\n" \
"            end\n" \
"            if padding.left ~= nil then\n" \
"                ftable:set_cell_prop(fort.ANY_ROW, column_index_map[col_name], fort.CPROP_LEFT_PADDING, padding.left)\n" \
"            end\n" \
"            if padding.bottom ~= nil then\n" \
"                ftable:set_cell_prop(fort.ANY_ROW, column_index_map[col_name], fort.CPROP_BOTTOM_PADDING, padding.bottom)\n" \
"            end\n" \
"            if padding.right ~= nil then\n" \
"                ftable:set_cell_prop(fort.ANY_ROW, column_index_map[col_name], fort.CPROP_RIGHT_PADDING, padding.right)\n" \
"            end\n" \
"        end\n" \
"    end\n" \
"\n" \
"    -- add cell spanning\n" \
"    if options.cell_span then\n" \
"        for row_index, cell_span in pairs(options.cell_span) do\n" \
"            for col_name, span in pairs(cell_span) do\n" \
"                -- only add header offset when positive indices\n" \
"                if row_index > 0 then\n" \
"                    row_index = row_index + header_row_offset\n" \
"                else\n" \
"                    row_index = row_index + footer_row_offset\n" \
"                end\n" \
"                ftable:set_cell_span(row_index, column_index_map[col_name], span)\n" \
"            end\n" \
"        end\n" \
"    end\n" \
"\n" \
"    --- add footer spanning\n" \
"    if options.footer and options.footer_span then\n" \
"        for col_name, span in pairs(options.footer_span) do\n" \
"            -- will be the last index\n" \
"            ftable:set_cell_span(-1, footer_index_map[col_name], span)\n" \
"        end\n" \
"    end\n" \
"\n" \
"    if options.frame ~= nil then\n" \
"        assert(border_style_mapping[options.frame], \"tabulate: invalid border style\")\n" \
"        ftable:set_border_style(border_style_mapping[options.frame])\n" \
"    end\n" \
"\n" \
"    return ftable\n" \
"end\n" \
"\n" \
"---convenience call to tabulate.tabulate\n" \
"---@param data tabulate.Data\n" \
"---@param options tabulate.Options\n" \
"---@return fort\n" \
"function tabulate:__call(data, options)\n" \
"    return self.tabulate(data, options)\n" \
"end\n" \
"\n" \
"---@class tabulate.GridOptions\n" \
"---@field public padding? tabulate.Padding\n" \
"---@field public frame? tabulate.Frame defaults to 'empty'\n" \
"---@field public align? table<integer, table<integer, tabulate.Align>>\n" \
"\n" \
"--- Create a grid of tables\n" \
"---@param table_grid string[][]\n" \
"---@param options? tabulate.GridOptions\n" \
"---@return fort\n" \
"function tabulate.grid(table_grid, options)\n" \
"    options = options or {}\n" \
"\n" \
"    options.frame = options.frame or 'empty'\n" \
"\n" \
"    ---@type table<string, string>>[]\n" \
"    local table_map = {}\n" \
"    local table_cols = {}\n" \
"    for row, table_row in ipairs(table_grid) do\n" \
"        table_map[row] = {}\n" \
"        for col, dtable in ipairs(table_row) do\n" \
"            table_map[row][tostring(col)] = dtable\n" \
"            if #table_cols < col then\n" \
"                table.insert(table_cols, tostring(col))\n" \
"            end\n" \
"        end\n" \
"\n" \
"    end\n" \
"    return tabulate.tabulate(table_map, {\n" \
"        column = table_cols,\n" \
"        ---@diagnostic disable-next-line: assign-type-mismatch\n" \
"        align = options.align,\n" \
"        col_padding = options.padding,\n" \
"        frame = options.frame,\n" \
"        show_header = false\n" \
"    })\n" \
"end\n" \
"\n" \
"return tabulate\n";
