"cursor.jump = cursor['goto']\n" \
"\n" \
"return cursor\n";
static const char lualib_time_code[] = "--- A simple implementation of time using a monotonic clock.\n" \
"--- Do not use this for accurate dates. Only for measuring changes in time.\n" \
"local _time = require \"_time\"\n" \
"\n" \
"---@module 'time'\n" \
"local time = {}\n" \
"\n" \
"---Sleep for a duration of time\n" \
"---@param secs number\n" \
"function time.sleep(secs)\n" \
"    _time.sleep(secs)\n" \
"end\n" \
"\n" \
"---Get the epoch time\n" \
"---@return number\n" \
"function time.time()\n" \
"    return _time.time()\n" \
"end\n" \
"\n" \
"---Get the monotonic clock time (Not the epoch time)\n" \
"---Use only for measuring changes in time, not dates.\n" \
"---@return number\n" \
"function time.monotonic()\n" \
"    return _time.monotonic()\n" \
"end\n" \
"\n" \
"---Get the thread time\n" \
"---Use only for measuring changes in time, not dates.\n" \
"---@return number\n" \
"function time.thread_time()\n" \
"    return _time.thread_time()\n" \
"end\n" \
"\n" \
"---Get the process time\n" \
"---Use only for measuring changes in time, not dates.\n" \
"---@return number\n" \
"function time.process_time()\n" \
"    return _time.process_time()\n" \
"end\n" \
"\n" \
"return time\n";
static const char lualib_timedelta_code[] = "local timedelta = {}\n" \
"\n" \
"local function divmod(a, b)\n" \
"    local q = a // b\n" \
"    local r = a % b\n" \
"    return q, r\n" \
"end\n" \
"\n" \
"---Pretty print time delta as dd:hh:mm:ss.MMM?\n" \
"---@param duration_sec number\n" \
"---@param millisecond? boolean display milliseconds\n" \
"function timedelta.pretty(duration_sec, millisecond)\n" \
"    local sign_str = choose(duration_sec < 0, '-', '')\n" \
"    local seconds = math.floor(math.abs(duration_sec))\n" \
"\n" \
"    local days, hours, minutes\n" \
"\n" \
"    days, seconds = divmod(seconds, 86400)\n" \
"    hours, seconds = divmod(seconds, 3600)\n" \
"    minutes, seconds = divmod(seconds, 60)\n" \
"\n" \
"    local output = {}\n" \
"\n" \
"    table.insert(output, sign_str)\n" \
"    if days > 0 then\n" \
"        table.insert(output, \"%dd\" % {days})\n" \
"    end\n" \
"    if days > 0 or hours > 0 then\n" \
"        table.insert(output, \"%02d:\" % {hours})\n" \
"    end\n" \
"    table.insert(output, \"%02d:%02d\" % {minutes, seconds})\n" \
"    if millisecond then\n" \
"        local _, m = math.modf(duration_sec)\n" \
"        table.insert(output, string.sub(\"%.3f\" % {math.abs(m)}, 2))\n" \
"    end\n" \
"    return table.concat(output)\n" \
"end\n" \
"\n" \
"function timedelta.datetime_iso8601(timestamp)\n" \
"    local base_time, milliseconds = math.modf(timestamp)\n" \
"    return os.date(\"%Y-%m-%dT%H:%M:%S\", base_time) .. string.sub((\"%.3f\") % {milliseconds}, 2) ..\n" \
"               os.date(\"%z\", base_time)\n" \
"end\n" \
"\n" \
"function timedelta.timestamp_iso8601(timestamp)\n" \
"    local base_time, milliseconds = math.modf(timestamp)\n" \
"    return os.date(\"%H:%M:%S\", base_time) .. string.sub((\"%.3f\") % {milliseconds}, 2) .. os.date(\"%z\", base_time)\n" \
"end\n" \
"\n" \
"return timedelta\n";
static const char lualib_toolbox_prbs_code[] = "local itools = require \"itertools\"\n" \
"\n" \
"local prbs = {}\n" \
"\n" \
"---Determine RX settings that would lock for PRBS.\n" \
"---@important locks here does not mean it has found the \"correct\" settings. TX may need changes for general usage.\n" \
"---@param slice integer\n" \
"---@param lanes integer[]\n" \
"---@param threshold? number default 1e-5\n" \
"function prbs.find_rx_lock(slice, lanes, threshold)\n" \
"    if threshold == nil then\n" \
"        threshold = 1e-5\n" \
"    end\n" \
"    local polmap_choices = {}\n" \
"    for _ in iter(lanes) do\n" \
"        list.append(polmap_choices, itools.values({0, 1}))\n" \
"    end\n" \
"    local failed_lanes = {}\n" \
"    for lane in iter(lanes) do\n" \
"        print(\"Locking Lane %d\" % {lane})\n" \
"\n" \
"        local initial_state = {\n" \
"            pol = credo.serdes_get_rx_polarity(slice, lane),\n" \
"            msb = credo.serdes_get_rx_msb(slice, lane),\n" \
"            pc = credo.serdes_get_rx_precoder(slice, lane)\n" \
"        }\n" \
"\n" \
"        for pol, msb, pc in itools.product(itools.values({0, 1}), itools.values({false, true}),\n" \
"                                           itools.values({false, true})) do\n" \
"            print(\"polarities:\", pol, \"msblsb: %s\" % {msb}, \"precoder: %s\" % {pc})\n" \
"            credo.serdes_set_rx_polarity(slice, lane, pol)\n" \
"            credo.serdes_set_rx_msb(slice, lane, msb)\n" \
"            credo.serdes_set_rx_precoder(slice, lane, pc)\n" \
"            -- need to trigger an auto sync on the prbs\n" \
"            credo.prbs_reset_rx_count(slice, lane)\n" \
"            -- we could use rx_lock, but not all chips / lane modes support it\n" \
"            local ber = credo.prbs_get_rx_ber(slice, lane, 0.1)\n" \
"            if ber < threshold then\n" \
"                print(\"Lane locked!\")\n" \
"                goto next_lane\n" \
"            end\n" \
"        end\n" \
"        list.append(failed_lanes, lane)\n" \
"        print(\"Failed to lock -- Restoring to initial state\")\n" \
"        credo.serdes_set_rx_polarity(slice, lane, initial_state.pol)\n" \
"        credo.serdes_set_rx_msb(slice, lane, initial_state.msb)\n" \
"        credo.serdes_set_rx_precoder(slice, lane, initial_state.pc)\n" \
"        ::next_lane::\n" \
"    end\n" \
"\n" \
"    if #failed_lanes > 0 then\n" \
"        pprint(\"Failed to lock on the lanes\", failed_lanes)\n" \
"        return\n" \
"    end\n" \
"    print(\"Successfully locked on all lanes\")\n" \
"end\n" \
"\n" \
"return prbs\n";
static const char lualib_toolbox_rsfec_code[] = "local time = require \"time\"\n" \
"local itools = require \"itertools\"\n" \
"\n" \
"local rsfec = {}\n" \
"---Iterate through the rx pol, rx msblsb, rx precoder on the given port lanes until hopefully the FEC is able to align.\n" \
"---It **should** be the rx polarity that should fix it, but we may as well be sure nothing weird is going on.\n" \
"---@important If it does lock it does not necessarily mean these are the truly correct settings. The TX could be wrong.\n" \
"---@param slice integer\n" \
"---@param port integer\n" \
"---@param side credo.Side\n" \
"function rsfec.find_fec_align(slice, port, side)\n" \
"    local port_config = credo.port_query(slice, port)\n" \
"\n" \
"    assert(port_config.port_id ~= credo.PORT_UNCONFIGURED, \"port is not configured\")\n" \
"\n" \
"    ---@type integer[]\n" \
"    local lanes\n" \
"    if side == credo.SIDE_HOST then\n" \
"        lanes = range(port_config.host_start_lane, port_config.host_start_lane + port_config.host_no_of_lanes - 1)\n" \
"    else\n" \
"        lanes = range(port_config.line_start_lane, port_config.line_start_lane + port_config.line_no_of_lanes - 1)\n" \
"    end\n" \
"\n" \
"    local polmap_choices = {}\n" \
"    for _ in iter(lanes) do\n" \
"        list.append(polmap_choices, itools.values({0, 1}))\n" \
"    end\n" \
"\n" \
"    local initial_state = {pol = {}, msb = {}, pc = {}}\n" \
"\n" \
"    for lane in iter(lanes) do\n" \
"        initial_state.pol[lane] = credo.serdes_get_rx_polarity(slice, lane)\n" \
"        initial_state.msb[lane] = credo.serdes_get_rx_msb(slice, lane)\n" \
"        initial_state.pc[lane] = credo.serdes_get_rx_precoder(slice, lane)\n" \
"    end\n" \
"\n" \
"    for polarities in itools.product_table(table.unpack(polmap_choices)) do\n" \
"\n" \
"        for idx, lane in ipairs(lanes) do\n" \
"            credo.serdes_set_rx_polarity(slice, lane, polarities[idx])\n" \
"        end\n" \
"        for msb, pc in itools.product(itools.values({false, true}), itools.values({false, true})) do\n" \
"            print(\"polarities:\", polarities, \"msblsb: %s\" % {msb}, \"precoder: %s\" % {pc})\n" \
"            for lane in iter(lanes) do\n" \
"                credo.serdes_set_rx_msb(slice, lane, msb)\n" \
"                credo.serdes_set_rx_precoder(slice, lane, pc)\n" \
"            end\n" \
"            time.sleep(0.5)\n" \
"            local align = credo.rsfec_get_align_status(slice, port, side)\n" \
"            print(\"aligned:\", align.fec_aligned, \"AM_locked\", align.AM_locked)\n" \
"            if align.fec_aligned then\n" \
"                print(\"FEC is aligned!\")\n" \
"                return\n" \
"            end\n" \
"        end\n" \
"    end\n" \
"    print(\"FEC is not aligned\")\n" \
"\n" \
"    print(\"Restoring to initial state\")\n" \
"    for lane in iter(lanes) do\n" \
"        credo.serdes_set_rx_polarity(slice, lane, initial_state.pol[lane])\n" \
"        credo.serdes_set_rx_msb(slice, lane, initial_state.msb[lane])\n" \
"        credo.serdes_set_rx_precoder(slice, lane, initial_state.pc[lane])\n" \
"    end\n" \
"end\n" \
"\n" \
"return rsfec\n";
static const char lualib_typings_code[] = "-- file to add typing features for lua LSP\n" \
"-- correctly allow penlight string percent operator (like python) \"%d\" % {2} to return string\n" \
"---@class string\n" \
"---@operator mod: string\n" \
"---@operator mul: string\n" \
"---@operator add: string   \"test\" + \"test\"\n" \
"\n" \
"\n" \
"---@class integer\n" \
"---@field value integer\n";
static const char lualib_webbrowser_code[] = "local compat = require \"pl.compat\"\n" \
"\n" \
"---@module 'webbrowser'\n" \
"local webbrowser = {}\n" \
"\n" \
"-- From: https://stackoverflow.com/questions/11163748/open-web-browser-using-lua-in-a-vlc-extension#18864453\n" \
"-- Attempts to open a given URL in the system default browser, regardless of Operating System.\n" \
"local open_cmd = function(url)\n" \
"    -- we will assume linux if check fails\n" \
"    os.execute('xdg-open \"%s\"' % {url})\n" \
"end -- this needs to stay outside the function, or it'll re-sniff every time...\n" \
"\n" \
"---open webbrowser to url or file\n" \
"---@param url string\n" \
"function webbrowser.open(url)\n" \
"    open_cmd(url)\n" \
"end\n" \
"\n" \
"pcall(function()\n" \
"    if compat.is_windows then -- windows\n" \
"        open_cmd = function(url)\n" \
"            -- Should work on anything since (and including) win'95\n" \
"            os.execute('start \"%s\"' % {url})\n" \
"        end\n" \
"    else -- that ought to only leave Linux\n" \
"        open_cmd = function(url)\n" \
"            -- should work on X-based distros.\n" \
"            os.execute('xdg-open \"%s\"' % {url})\n" \
"        end\n" \
"    end\n" \
"end)\n" \
"\n" \
"return webbrowser\n";
static const char lualib_zlib_code[] = "local miniz = require \"miniz\"\n" \
"\n" \
"---@module 'zlib'\n" \
"local zlib = {}\n" \
"\n" \
"---@alias bytes string\n" \
"\n" \
"---compress string (data will not be readable or printable)\n" \
"---@param data string\n" \
"---@param level? integer\n" \
"---@param window_size? integer\n" \
"---@return bytes bytes\n" \
"function zlib.compress(data, level, window_size)\n" \
"    return miniz.compress(data, level, window_size)\n" \
"end\n" \
"\n" \
"---decompress string (data will not be readable or printable)\n" \
"---@param data string\n" \
"---@param level? integer\n" \
"---@param window_size? integer\n" \
"---@return string data\n" \
"function zlib.decompress(data, level, window_size)\n" \
"    return miniz.decompress(data, level, window_size)\n" \
"end\n" \
"\n" \
"---Computes an Adler-32 checksum of data.\n" \
"---@param data string\n" \
"---@param prev? integer\n" \
"---@return integer\n" \
"function zlib.adler32(data, prev)\n" \
"    return miniz.adler32(data, prev)\n" \
"end\n" \
"\n" \
"---Computes a CRC (Cyclic Redundancy Check) checksum of data.\n" \
"---@param data string\n" \
"---@param prev? integer\n" \
"---@return integer\n" \
"function zlib.crc32(data, prev)\n" \
"    return miniz.crc32(data, prev)\n" \
"end\n" \
"\n" \
"return zlib\n";
