static const LibraryModule_t loader = {
.name="loader",
.code=lualib_loader_code,
.size=sizeof(lualib_loader_code),
.bcode=NULL,
.bsize=0
};

#define COUNT_OF(array) ((sizeof(array) / sizeof(0 [array])) / ((size_t)(!(sizeof(array) % sizeof(0 [array])))))

// copied from lstrlib,c from string.dump function

/*
** Buffer to store the result of 'string.dump'. It must be initialized
** after the call to 'lua_dump', to ensure that the function is on the
** top of the stack when 'lua_dump' is called. ('luaL_buffinit' might
** push stuff.)
*/
struct str_Writer {
    int init; /* true iff buffer has been initialized */
    luaL_Buffer B;
};

static int writer(lua_State* L, const void* b, size_t size, void* ud) {
    struct str_Writer* state = (struct str_Writer*)ud;
    if (!state->init) {
        state->init = 1;
        luaL_buffinit(L, &state->B);
    }
    luaL_addlstring(&state->B, (const char*)b, size);
    return 0;
}

static int mod_cmpfunc(const void* target, const void* mod) {
    return strcmp((const char*)target, ((const LibraryModule_t*)mod)->name);
}

// binary search
LibraryModule_t* lib_search(const char* target) {
    return bsearch(target, libraries, COUNT_OF(libraries), sizeof(LibraryModule_t), mod_cmpfunc);
}

static int llibs_get_module(lua_State* L) {
    const char* module = luaL_checkstring(L, 1);

    LibraryModule_t* mod = lib_search(module);
    if (mod == NULL) {  // couldnt find the module
        return 0;
    }
    lua_pushstring(L, mod->code);
    return 1;
}

typedef struct {
    pthread_mutex_t lock;
    bool cached;
} BundleState_t;

static BundleState_t gBundle = {.lock = PTHREAD_MUTEX_INITIALIZER, .cached = false};

static inline void cache_libraries(lua_State* L) {
    for (size_t i = 0; i < COUNT_OF(libraries); i++) {
        LibraryModule_t* lmodule = &libraries[i];
        lua_pushfstring(L, "=%s", lmodule->name);
        const char* chunkname = lua_tostring(L, -1);
        luaL_loadbufferx(L, lmodule->code, lmodule->size - 1, chunkname, "t");
        struct str_Writer state;
        state.init = 0;
        int err = lua_dump(L, writer, &state, 0);
        if (err != LUA_OK) {
            lua_pop(L, 2);  // remove chunkname + compiled code
            continue;
        }
        size_t bsize;
        luaL_pushresult(&state.B);
        const char* bcode = lua_tolstring(L, -1, &bsize);
        lmodule->bcode = malloc(bsize);
        if (lmodule->bcode != NULL) {
            lmodule->bsize = bsize;
            memcpy(lmodule->bcode, bcode, bsize);
        }
        lua_pop(L, 3);  // remove chunkname + compiled code + buffer
    }
    gBundle.cached = true;  // it is now fully cached
}

static int llibs_load_module(lua_State* L) {
    const char* module = luaL_checkstring(L, 1);
    const char* chunkname = luaL_checkstring(L, 2);

    // if cache is not complete
    if (luai_unlikely(!gBundle.cached)) {
        pthread_mutex_lock(&gBundle.lock);
        if (!gBundle.cached) {  // ensure another thread did not perform the caching
            cache_libraries(L);
        }
        pthread_mutex_unlock(&gBundle.lock);
    }

    LibraryModule_t* lmodule = lib_search(module);
    if (lmodule == NULL) {  // couldnt find the module
        lua_pushfstring(L, "no bundled module '%s'", module);
        return 1;
    }

    if (luai_likely(lmodule->bcode != NULL)) {
        luaL_loadbufferx(L, lmodule->bcode, lmodule->bsize, chunkname, "b");
    } else {
        // for some reason caching didnt happen
        luaL_loadbufferx(L, lmodule->code, lmodule->size - 1, chunkname, "t");
    }
    return 1;
}

static int llibs_get_module_list(lua_State* L) {
    lua_newtable(L);
    for (size_t i = 0; i < COUNT_OF(libraries); i++) {
        LibraryModule_t* lmodule = &libraries[i];
        lua_pushinteger(L, (lua_Integer)i + 1);
        lua_pushstring(L, lmodule->name);
        lua_settable(L, -3);
    }
    return 1;
}

static const struct luaL_Reg libs_functions[] = {
    {"get_module", llibs_get_module},
    {"get_module_list", llibs_get_module_list},
    {"load_module", llibs_load_module},
    {NULL, NULL},
};

int luaopen__libs(lua_State* L) {
    luaL_newlib(L, libs_functions);
    return 1;
}

int luaopen__loader(lua_State* L) {
    int err = luaL_dostring(L, loader.code);
    if (err != LUA_OK) {
        lua_writestringerror(L, "%s\n", "Unable to inject lua bootloader");
        lua_writestringerror(L, "%s", lua_tostring(L, -1));
    }
    return 0;
}
